def _gewa_default_multiplier(family: str) -> float:
    if "C6H" in family:
        return 3.00
    if "C5H" in family:
        return 2.80
    if "C+SL" in family or "C+LW" in family:
        return 2.40
    if "CLF" in family:
        return 2.80
    if "CPL" in family:
        return 2.20
    return 2.50


def _install_wieland_gewa_options() -> None:
    for row in WIELAND_GEWA_ROWS:
        matinfo = WIELAND_MATERIALS[row["mat"]]
        name = f"Wieland {row['family']} {row['tube_size']} x {row['wall_nom_mm']:.2f} {row['mat']}"
        service = "Sea water" if matinfo["seawater"] is True else ("Sea water conditional" if matinfo["seawater"] == "conditional" else "Plain / fresh water")
        if row["family"] in ("GEWA-C6H", "GEWA-C5H", "GEWA-C+SL", "GEWA-C+LW"):
            application_note = "High performance fresh/closed water condenser tube."
        elif row["family"] == "GEWA-CLF":
            application_note = "CLF family: for seawater/increased fouling applications when material is suitable."
        else:
            application_note = "CPL family: for high fouling applications."
        FINNED_TUBE_OPTIONS[name] = {
            "type": row["family"],
            "compatible_material_contains": [matinfo["app_material"]],
            "area_per_m": math.pi * row["d4_mm"] / 1000.0,
            "weight_kg_m": row["kg_m"],
            "root_od_mm": row["d3_mm"],
            "fin_od_mm": row["d4_mm"],
            "inside_d_mm": row["d2_mm"],
            "plain_end_od_mm": row["d1_mm"],
            "plain_end_wall_mm": row["s1_mm"],
            "wall_under_fin_mm": row["s2_mm"],
            "wieland_material_code": row["mat"],
            "wieland_material_name": matinfo["name"],
            "water_service": service,
            "htc_mult_cond": _gewa_default_multiplier(row["family"]),
            "htc_mult_desup": 1.15,
            "htc_mult_sub": 1.20,
            "seawater_suitable": bool(matinfo["seawater"]),
            "source": "Wieland GEWA-C condenser tube catalogue",
            "note": f"{application_note} Material {row['mat']} = {matinfo['name']}. Geometry: d1={row['d1_mm']:.2f} mm, d4={row['d4_mm']:.2f} mm, d3={row['d3_mm']:.2f} mm, d2={row['d2_mm']:.2f} mm, weight={row['kg_m']:.3f} kg/m. {matinfo['note']}"
        }

_install_wieland_gewa_options()


def enhanced_options_for_base_tube(tube_material: str, tube_size: str, water_service: str = "Sea water") -> List[str]:
    """Return enhanced tube options compatible with selected water service, material and OD.

    For seawater the app shows only materials normally suitable for seawater service
    (Cu-Ni L10/L30, conditional aluminium brass S76, and custom titanium options).
    For plain/fresh water the app also shows copper K21 and carbon-steel options.
    """
    base_od_mm = TUBE_SIZES[tube_size]["od"] * 1000.0
    seawater_mode = str(water_service).startswith("Sea")
    allowed: List[str] = []
    for name, opt in FINNED_TUBE_OPTIONS.items():
        typ = opt.get("type", "plain")
        if typ == "plain":
            allowed.append(name)
            continue
        if typ == "custom":
            allowed.append(name)
            continue
        if name.startswith("Datang"):
            if "Titanium" in tube_material and 12.7 <= base_od_mm <= 31.75:
                allowed.append(name)
            continue
        is_gewa = str(typ).startswith("GEWA") or name.startswith("Wieland")
        comp = opt.get("compatible_material_contains", [])
        material_ok = (not comp) or any(c in tube_material for c in comp)
        plain_od = opt.get("plain_end_od_mm") or opt.get("fin_od_mm")
        od_ok = True if plain_od is None else abs(float(plain_od) - base_od_mm) <= 0.35
        service_ok = True
        if is_gewa:
            service = opt.get("water_service", "Plain / fresh water")
            mat_code = opt.get("wieland_material_code", "")
            if seawater_mode:
                # Direct seawater: show only CLF/CPL or other rows where material/service is acceptable.
                # Copper K21 and carbon steel are deliberately hidden for direct seawater.
                material_service_ok = mat_code in ("L10", "L30", "S76") or "Titanium" in tube_material
                family_service_ok = ("CLF" in typ) or ("CPL" in typ)
                service_ok = material_service_ok and family_service_ok
            else:
                service_ok = True
        elif seawater_mode and opt.get("seawater_suitable") is False:
            service_ok = False
        if material_ok and od_ok and service_ok:
            allowed.append(name)
    return allowed or ["Plain smooth tube", "User-defined enhanced tube"]

def plain_tube_weight_per_m(do: float, di: float, tube_material: str) -> float:
    """Plain tube metal weight per metre, kg/m."""
    rho = TUBE_MATERIALS.get(tube_material, {}).get("density", 8000)
    return (math.pi / 4.0) * max(do**2 - di**2, 0.0) * rho


def low_fin_outside_area_per_m(fin_od_m: float, root_od_m: float, fins_per_inch: float, fin_thickness_m: float) -> float:
    """Approximate actual outside area per metre for integral low-fin tubes.

    The formula treats each fin as two annular faces plus a small tip area,
    and includes exposed root-cylinder area between fins. It is a geometry
    estimate for screening; supplier catalogue area per metre should be used
    when available.
    """
    if fin_od_m <= 0 or root_od_m <= 0 or fins_per_inch <= 0:
        return math.pi * max(fin_od_m, root_od_m)
    fins_per_m = fins_per_inch / 0.0254
    pitch_m = 1.0 / fins_per_m
    t = clamp(fin_thickness_m, 0.00005, 0.80 * pitch_m)
    root_exposed = math.pi * root_od_m * max(pitch_m - t, 0.0) * fins_per_m
    fin_faces = fins_per_m * (math.pi / 2.0) * max(fin_od_m**2 - root_od_m**2, 0.0)
    fin_tips = fins_per_m * math.pi * fin_od_m * t
    return root_exposed + fin_faces + fin_tips


def low_fin_defaults_for_selected_tube(tube_material: str, tube_size: str, bwg: str, fins_per_inch: float, fin_height_mm: float, fin_thickness_mm: float) -> Dict[str, float]:
    """Catalogue-style low-fin geometry defaults for the selected base tube.

    For low-fin condenser tubes the plain end OD remains the nominal tube OD.
    The fin OD is therefore taken as the selected tube OD, while the fin root
    OD is reduced by twice the fin height.
    """
    do = TUBE_SIZES[tube_size]["od"]
    wall = TUBE_SIZES[tube_size]["bwg"][bwg]
    di = max(do - 2 * wall, 0.001)
    plain_area = math.pi * do
    fin_h = max(0.0, fin_height_mm / 1000.0)
    root_od = max(di + 0.0003, do - 2.0 * fin_h)
    area = low_fin_outside_area_per_m(do, root_od, fins_per_inch, fin_thickness_mm / 1000.0)
    # Low-fin rolling usually changes the metal distribution, but without exact supplier
    # mass data we keep a conservative weight factor instead of pretending exactness.
    plain_weight = plain_tube_weight_per_m(do, di, tube_material)
    weight_factor = clamp(1.0 + 0.10 * max(area / plain_area - 1.0, 0.0), 1.05, 1.35)
    return {
        "plain_area_m2_m": plain_area,
        "area_m2_m": area,
        "area_ratio": area / plain_area if plain_area > 0 else 1.0,
        "plain_weight_kg_m": plain_weight,
        "weight_kg_m": plain_weight * weight_factor,
        "inside_d_mm": di * 1000.0,
        "root_od_mm": root_od * 1000.0,
        "fin_od_mm": do * 1000.0,
        "fins_per_inch": fins_per_inch,
        "fin_height_mm": fin_height_mm,
        "fin_thickness_mm": fin_thickness_mm,
    }


def enhanced_defaults_for_selected_tube(option_name: str, tube_material: str, tube_size: str, bwg: str) -> Dict[str, float]:
    """Return physically consistent default enhanced-tube data for the SAME selected tube.

    For exact catalogue rows, use catalogue area/ID/weight.
    For range/custom rows such as Datang, estimate defaults from the selected base tube
    so the enhancement never silently remains equal to a plain tube.
    """
    opt = FINNED_TUBE_OPTIONS.get(option_name, FINNED_TUBE_OPTIONS["Plain smooth tube"])
    do = TUBE_SIZES[tube_size]["od"]
    wall = TUBE_SIZES[tube_size]["bwg"][bwg]
    di = do - 2 * wall
    plain_area = math.pi * do
    plain_weight = plain_tube_weight_per_m(do, di, tube_material)
    if opt.get("area_per_m"):
        area = float(opt["area_per_m"])
    else:
        area = plain_area * float(opt.get("default_area_ratio", 1.0))
    if opt.get("weight_kg_m"):
        weight = float(opt["weight_kg_m"])
    else:
        weight = plain_weight * float(opt.get("default_weight_factor", 1.0))
    if opt.get("inside_d_mm"):
        id_mm = float(opt["inside_d_mm"])
    else:
        id_mm = di * 1000.0
    return {
        "plain_area_m2_m": plain_area,
        "area_m2_m": area,
        "area_ratio": area / plain_area if plain_area > 0 else 1.0,
        "plain_weight_kg_m": plain_weight,
        "weight_kg_m": weight,
        "inside_d_mm": id_mm,
    }


