def catalogue_matches(results: Dict[str, object], top_n: int = 12) -> pd.DataFrame:
    """Return closest catalogue models with simple derating guidance.

    This is a benchmark tool, not a certified rerating. It compares required kW,
    shell OD, length, water flow and service/material suitability, then applies a
    rough derating when the current fouling/water temperatures are more severe
    than the catalogue basis.
    """
    rows = []
    inp = results.get("inputs")
    req_kw = float(results.get("q_total_kw", 0.0))
    req_flow = float(results.get("vol_sw_m3h", 0.0))
    req_od = float(results.get("shell_od_mm", 0.0))
    req_len = float(results.get("tube_length_m", 0.0)) * 1000.0
    sw_in = float(results.get("t_sw_in_c", 30.0))
    cond = float(results.get("t_ref_cond_c", 45.0))
    fouling = float(getattr(inp, "fouling_seawater", 0.0001)) if inp else 0.0001
    is_seawater = bool(inp and ("Titanium" in inp.tube_material or "Cu-Ni" in inp.tube_material or fouling >= 0.00008))

    for m in CATALOGUE_MODELS:
        cat_kw = float(m["Catalog kW"])
        source = m["Source"]
        # Approximate basis conditions by catalogue family.
        if "HSTAR/Wieland GEWA" in source:
            basis_cond, basis_w_in, basis_ff = 47.0, 37.0, 0.000044
        elif "BITZER K seawater" in source:
            basis_cond, basis_w_in, basis_ff = 35.0, 25.0, 0.000086
        elif "BITZER CRM" in source:
            basis_cond, basis_w_in, basis_ff = 40.0, 30.0, 0.000086
        elif "ONDA" in source:
            basis_cond, basis_w_in, basis_ff = 41.5, 30.0, 0.000043
        else:  # Trane/ACME MHX roughly 105F condensing, 85F water in
            basis_cond, basis_w_in, basis_ff = 40.6, 29.4, 0.000125

        approach_basis = max(1.0, basis_cond - basis_w_in)
        approach_user = max(1.0, cond - sw_in)
        lmtd_factor = clamp(approach_user / approach_basis, 0.45, 1.45)
        # Fouling penalty; intentionally mild because geometry/rating details are unknown.
        fouling_factor = clamp(1.0 - 0.55 * max(0.0, fouling - basis_ff) / max(0.0003, basis_ff + 0.0001), 0.70, 1.05)
        service_factor = 1.0
        if is_seawater and m["Service"] != "Seawater":
            service_factor = 0.75
        adjusted_kw = cat_kw * lmtd_factor * fouling_factor * service_factor
        margin_pct = (adjusted_kw / req_kw - 1.0) * 100.0 if req_kw > 0 else 0.0
        size_score = abs(adjusted_kw - req_kw) / max(req_kw, 1.0)
        flow_score = abs(float(m["Water flow m3/h"]) - req_flow) / max(req_flow, 1.0)
        od_score = abs(float(m["Shell OD mm"]) - req_od) / max(req_od, 100.0) if req_od > 0 else 0.0
        len_score = abs(float(m["Length mm"]) - req_len) / max(req_len, 500.0) if req_len > 0 else 0.0
        service_penalty = 0.35 if is_seawater and m["Service"] != "Seawater" else 0.0
        score = 0.55 * size_score + 0.15 * flow_score + 0.15 * od_score + 0.10 * len_score + service_penalty
        verdict = "Candidate" if adjusted_kw >= req_kw else "Undersized"
        if is_seawater and m["Service"] != "Seawater":
            verdict = "Material mismatch for seawater"
        rows.append({**m, "Adjusted kW est.": adjusted_kw, "Margin %": margin_pct, "Score": score, "Benchmark verdict": verdict})
    df = pd.DataFrame(rows).sort_values(["Score", "Adjusted kW est."], ascending=[True, False]).head(top_n).reset_index(drop=True)
    return df


# =============================================================================
# UTILITY CALCULATIONS
# =============================================================================

def safe_log_mean(dt1: float, dt2: float) -> float:
    if dt1 <= 0 or dt2 <= 0:
        return float("nan")
    if abs(dt1 - dt2) < 1e-9:
        return dt1
    return (dt1 - dt2) / math.log(dt1 / dt2)


def clamp(value: float, low: float, high: float) -> float:
    return max(low, min(high, value))


def seawater_props(temp_c: float, salinity_gkg: float = 35.0) -> Dict[str, float]:
    """Practical approximate seawater properties near HVAC condenser range."""
    # Conservative polynomial-ish estimates adequate for screening.
    T = temp_c
    rho = 1027 - 0.25 * (T - 20) + 0.75 * ((salinity_gkg - 35) / 5)
    cp = 3990 - 2.0 * (T - 25)
    k = 0.596 + 0.0015 * (T - 20)
    # Pa.s, rough decrease with temperature
    mu = 0.00108 * math.exp(-0.023 * (T - 20))
    pr = cp * mu / k
    return {"rho": rho, "cp": cp, "k": k, "mu": mu, "pr": pr}


def refrigerant_props(ref: str, t_cond_c: float, t_discharge_c: float) -> Dict[str, float]:
    """Get saturated and superheated refrigerant properties. CoolProp if available, fallback otherwise."""
    fb = FREON_FALLBACK.get(ref, FREON_FALLBACK["R134a"]).copy()
    if not COOLPROP_AVAILABLE:
        fb.update({"source": "Fallback fixed-property table", "p_sat_kpa": float("nan")})
        return fb
    try:
        T_sat = t_cond_c + 273.15
        T_sup = max(t_discharge_c + 273.15, T_sat + 1.0)
        P_sat = CP.PropsSI("P", "T", T_sat, "Q", 0, ref)
        h_l = CP.PropsSI("H", "T", T_sat, "Q", 0, ref)
        h_v = CP.PropsSI("H", "T", T_sat, "Q", 1, ref)
        props = {
            "h_fg": h_v - h_l,
            "rho_l": CP.PropsSI("D", "T", T_sat, "Q", 0, ref),
            "rho_v": CP.PropsSI("D", "T", T_sat, "Q", 1, ref),
            "k_l": CP.PropsSI("L", "T", T_sat, "Q", 0, ref),
            "k_v": CP.PropsSI("L", "T", T_sat, "Q", 1, ref),
            "mu_l": CP.PropsSI("V", "T", T_sat, "Q", 0, ref),
            "mu_v": CP.PropsSI("V", "T", T_sat, "Q", 1, ref),
            "cp_l": CP.PropsSI("C", "T", T_sat, "Q", 0, ref),
            "cp_v": CP.PropsSI("C", "T", T_sup, "P", P_sat, ref),
            "sigma": CP.PropsSI("I", "T", T_sat, "Q", 0, ref),
            "p_sat_kpa": P_sat / 1000,
            "source": "CoolProp",
        }
        return props
    except Exception as e:
        fb.update({"source": f"Fallback fixed-property table; CoolProp failed: {e}", "p_sat_kpa": float("nan")})
        return fb


def friction_factor_churchill_like(Re: float, rel_rough: float = 0.00005) -> float:
    if Re <= 0:
        return float("nan")
    if Re < 2300:
        return 64 / Re
    # Haaland explicit approximation
    inv = -1.8 * math.log10((rel_rough / 3.7) ** 1.11 + 6.9 / Re)
    return 1 / inv**2


def gnielinski_htc(Re: float, Pr: float, k: float, D: float) -> Tuple[float, float]:
    if D <= 0 or k <= 0 or Pr <= 0 or Re <= 0:
        return float("nan"), float("nan")
    if Re < 2300:
        Nu = 4.36
    elif Re < 3000:
        Nu_lam = 4.36
        Nu_turb = 0.023 * 3000**0.8 * Pr**0.4
        Nu = Nu_lam + (Re - 2300) / 700 * (Nu_turb - Nu_lam)
    else:
        f = friction_factor_churchill_like(Re)
        Nu = (f / 8) * (Re - 1000) * Pr / (1 + 12.7 * (f / 8) ** 0.5 * (Pr ** (2 / 3) - 1))
        Nu = max(Nu, 4.36)
    return Nu * k / D, Nu


def shell_condensation_htc_nusselt_horizontal_bundle(refp: Dict[str, float], do: float, t_cond: float, t_wall_est: float, tube_rows: int) -> Tuple[float, float]:
    """Approximate shell-side film condensation coefficient outside horizontal tube bank.
    Uses Nusselt horizontal tube style with row correction n^-0.25.
    """
    dt = max(1.0, t_cond - t_wall_est)
    rho_l, rho_v = refp["rho_l"], refp["rho_v"]
    k_l, mu_l, hfg = refp["k_l"], refp["mu_l"], refp["h_fg"]
    row_corr = max(1.0, tube_rows) ** (-0.25)
    h_single = 0.725 * ((9.81 * rho_l * (rho_l - rho_v) * hfg * k_l**3) / (mu_l * do * dt)) ** 0.25
    h_bundle = h_single * row_corr
    return h_bundle, dt


def simple_shell_single_phase_htc(mdot: float, rho: float, mu: float, k: float, cp: float, area_cross: float, de: float) -> Tuple[float, float, float, float]:
    v = mdot / (rho * area_cross) if rho > 0 and area_cross > 0 else float("nan")
    Re = rho * v * de / mu if mu > 0 and de > 0 else float("nan")
    Pr = cp * mu / k if k > 0 else float("nan")
    if Re < 100:
        Nu = 1.0
    elif Re < 1000:
        Nu = 0.6 * Re**0.5 * Pr**0.33
    else:
        Nu = 0.36 * Re**0.55 * Pr**0.33
    h = Nu * k / de if de > 0 else float("nan")
    return h, Nu, Re, v


def tube_bundle_diameter(n_tubes: int, pitch: float, layout: str) -> float:
    # Practical estimate based on packing density. Conservative enough for screening.
    if n_tubes <= 0 or pitch <= 0:
        return float("nan")
    if "Triangular" in layout:
        packing = 0.82
    elif "Square" in layout:
        packing = 0.70
    else:
        packing = 0.74
    area_bundle = n_tubes * pitch**2 / packing
    return math.sqrt(4 * area_bundle / math.pi)


def equivalent_shell_diameter(pitch: float, do: float, layout: str) -> float:
    if "Triangular" in layout:
        return 4 * (0.433 * pitch**2 - math.pi * do**2 / 8) / (math.pi * do / 2)
    return 4 * (pitch**2 - math.pi * do**2 / 4) / (math.pi * do)


def tema_baffle_guidance(shell_id: float, baffle_spacing: float, tube_od: float, tube_material: str, t_metal: float) -> Dict[str, object]:
    min_spacing = max(shell_id / 5, 0.0508)  # 2 in minimum
    # Simplified unsupported span estimate by OD/material. A screening value, not certified table.
    od_in = tube_od / 0.0254
    if od_in <= 0.375:
        base_in = 35
    elif od_in <= 0.5:
        base_in = 44
    elif od_in <= 0.625:
        base_in = 52
    elif od_in <= 0.75:
        base_in = 60
    else:
        base_in = 74
    # Titanium/Cu-Ni stiffness lower than steel; keep same basic support screening but can be tightened.
    material_factor = 0.90 if "Titanium" in tube_material else 1.0
    max_span = base_in * 0.0254 * material_factor
    return {
        "min_spacing_m": min_spacing,
        "max_span_m": max_span,
        "min_spacing_ok": baffle_spacing >= min_spacing,
        "max_span_ok": baffle_spacing <= max_span,
        "note": "Screening guidance: confirm final support spans against TEMA table and vibration analysis.",
    }


def tube_hole_guidance(do: float) -> Dict[str, float]:
    # Common tube hole clearance guidance: OD + approx 0.1 mm for small tubes / 0.15-0.25 mm for larger.
    if do <= 0.0127:
        clearance = 0.00010
    elif do <= 0.01905:
        clearance = 0.00015
    else:
        clearance = 0.00020
    return {"tube_od_mm": do * 1000, "suggested_hole_mm": (do + clearance) * 1000, "diametral_clearance_mm": clearance * 1000}


def format_status(ok: Optional[bool]) -> str:
    if ok is None:
        return "N/A"
    return "OK" if ok else "NOT OK"


def format_pressure_drop(pa: float) -> str:
    """Format small pressure drops honestly.

    The shell-side refrigerant pressure drop in small HVAC condensers can be only a
    few Pa to tens of Pa. Showing only kPa with two decimals makes this appear as
    0.00 kPa, which is misleading.
    """
    if pa != pa:
        return "N/A"
    kpa = pa / 1000.0
    if abs(kpa) < 0.01:
        return f"{pa:.1f} Pa ({kpa:.4f} kPa)"
    if abs(kpa) < 1.0:
        return f"{kpa:.3f} kPa"
    return f"{kpa:.2f} kPa"


# =============================================================================
# DESIGN ENGINE
# =============================================================================

@dataclass
class CondenserInputs:
    q_total_kw: float
    refrigerant: str
    refrigerant_flow_mode: str
    user_mdot_ref_kg_s: float
    t_discharge_c: float
    t_cond_c: float
    subcooling_k: float
    seawater_in_c: float
    seawater_dt_k: float
    water_service: str
    seawater_flow_mode: str
    user_vol_sw_m3h: float
    salinity_gkg: float
    fouling_seawater: float
    fouling_refrigerant: float
    tube_material: str
    enhanced_tube_option: str
    user_enhanced_area_m2_m: float
    user_enhanced_weight_kg_m: float
    user_enhanced_id_mm: float
    user_enhanced_cond_mult: float
    enhanced_fpi: float
    enhanced_fin_height_mm: float
    enhanced_fin_thickness_mm: float
    shell_method: str
    shell_material: str
    tubesheet_material: str
    tube_size: str
    bwg: str
    tube_layout: str
    pitch_ratio: float
    tube_passes: int
    tube_length_m: float
    n_tubes: int
    baffle_cut_pct: float
    n_baffles: int
    shell_wall_mm: float
    max_package_length_m: float
    package_constraint_enabled: bool
    design_mode: str
    max_tube_velocity: float
    min_tube_velocity: float
    max_tube_dp_kpa: float
    max_shell_dp_kpa: float
    max_shell_velocity: float
    allocation_mode: str
    frac_desuperheat: float
    frac_condense: float
    frac_subcool: float
    auto_margin: float


class EngineeringCondenserDesigner:
    def __init__(self):
        pass

    def auto_select_geometry(self, base: CondenserInputs, refp: Dict[str, float], swp: Dict[str, float]) -> CondenserInputs:
        do = TUBE_SIZES[base.tube_size]["od"]
        wall = TUBE_SIZES[base.tube_size]["bwg"][base.bwg]
        di = do - 2 * wall
        pitch = base.pitch_ratio * do
        q = base.q_total_kw * 1000
        if getattr(base, "seawater_flow_mode", "Auto from water ΔT").startswith("Enter") and getattr(base, "user_vol_sw_m3h", 0.0) > 0:
            mdot_w = base.user_vol_sw_m3h * swp["rho"] / 3600.0
        else:
            mdot_w = q / (swp["cp"] * base.seawater_dt_k)
        # Choose tubes from velocity target, round to pass multiple.
        target_v = clamp((base.min_tube_velocity + base.max_tube_velocity) / 2, 0.8, base.max_tube_velocity)
        tubes_parallel = mdot_w / (swp["rho"] * target_v * math.pi * di**2 / 4)
        n_tubes = int(math.ceil(tubes_parallel * base.tube_passes / 2) * 2)
        n_tubes = max(base.tube_passes * 4, n_tubes)
        # quick U estimate to adjust tube length
        provisional = CondenserInputs(**{**base.__dict__, "n_tubes": n_tubes})
        # estimate area needed using conservative U 700 W/m2K if no prior calculation
        lmtd = safe_log_mean(base.t_cond_c - base.seawater_in_c, base.t_cond_c - (base.seawater_in_c + base.seawater_dt_k))
        conservative_u = 650 if "Titanium" in base.tube_material else 800
        opt = FINNED_TUBE_OPTIONS.get(getattr(base, "enhanced_tube_option", "Plain smooth tube"), FINNED_TUBE_OPTIONS["Plain smooth tube"])
        defaults = enhanced_defaults_for_selected_tube(getattr(base, "enhanced_tube_option", "Plain smooth tube"), base.tube_material, base.tube_size, base.bwg)
        if opt["type"] == "plain":
            area_per_m = defaults["plain_area_m2_m"]
        elif opt.get("area_per_m") is None:
            # User/custom value, falling back to an estimated enhanced value instead of plain area.
            area_per_m = float(getattr(base, "user_enhanced_area_m2_m", 0.0) or defaults["area_m2_m"])
        else:
            area_per_m = defaults["area_m2_m"]
        area_needed = q / (conservative_u * max(lmtd, 1.0)) * base.auto_margin
        length = area_needed / (area_per_m * n_tubes)
        length = clamp(length, 0.75, 6.0)
        return CondenserInputs(**{**base.__dict__, "n_tubes": n_tubes, "tube_length_m": length})

    def calculate(self, inp: CondenserInputs) -> Dict[str, object]:
        refp = refrigerant_props(inp.refrigerant, inp.t_cond_c, inp.t_discharge_c)
        sw_avg_t = inp.seawater_in_c + inp.seawater_dt_k / 2
        swp = seawater_props(sw_avg_t, inp.salinity_gkg)
        if inp.design_mode.startswith("Auto"):
            inp = self.auto_select_geometry(inp, refp, swp)
            swp = seawater_props(inp.seawater_in_c + inp.seawater_dt_k / 2, inp.salinity_gkg)

        do = TUBE_SIZES[inp.tube_size]["od"]
        wall = TUBE_SIZES[inp.tube_size]["bwg"][inp.bwg]
        di = do - 2 * wall
        pitch = inp.pitch_ratio * do
        k_tube = TUBE_MATERIALS[inp.tube_material]["k"]
        tube_opt = FINNED_TUBE_OPTIONS.get(getattr(inp, "enhanced_tube_option", "Plain smooth tube"), FINNED_TUBE_OPTIONS["Plain smooth tube"])
        # Use one physical tube definition.  Enhanced surface modifies the SAME selected tube.
        # Exact catalogue rows use their catalogue area/ID/weight. Range/custom rows use user input,
        # falling back to a realistic enhanced-area estimate instead of silently reverting to plain area.
        enh_defaults = enhanced_defaults_for_selected_tube(getattr(inp, "enhanced_tube_option", "Plain smooth tube"), inp.tube_material, inp.tube_size, inp.bwg)
        if tube_opt["type"] == "plain":
            enhanced_area_per_m = enh_defaults["plain_area_m2_m"]
            enhanced_weight_kg_m = None
            effective_di = di
        else:
            if tube_opt.get("area_per_m") is None:
                enhanced_area_per_m = float(getattr(inp, "user_enhanced_area_m2_m", 0.0) or enh_defaults["area_m2_m"])
            else:
                enhanced_area_per_m = float(tube_opt["area_per_m"])
            # Guard against accidental plain-tube value for an enhanced option.
            if enhanced_area_per_m <= enh_defaults["plain_area_m2_m"] * 1.02:
                enhanced_area_per_m = enh_defaults["area_m2_m"]
            enhanced_weight_kg_m = tube_opt.get("weight_kg_m") or (float(getattr(inp, "user_enhanced_weight_kg_m", 0.0)) or enh_defaults["weight_kg_m"])
            if tube_opt.get("inside_d_mm"):
                effective_di = tube_opt["inside_d_mm"] / 1000
            elif getattr(inp, "user_enhanced_id_mm", 0.0) > 0:
                effective_di = inp.user_enhanced_id_mm / 1000
            else:
                effective_di = enh_defaults["inside_d_mm"] / 1000
        plain_area_total = math.pi * do * inp.tube_length_m * inp.n_tubes
        area_total = enhanced_area_per_m * inp.tube_length_m * inp.n_tubes
        area_enhancement_ratio = area_total / plain_area_total if plain_area_total > 0 else 1.0
        tubes_per_pass = max(1, inp.n_tubes / inp.tube_passes)

        # Heat balance by refrigerant zones
        dh_desup = max(0.0, refp["cp_v"] * (inp.t_discharge_c - inp.t_cond_c))
        dh_cond = refp["h_fg"]
        dh_sub = max(0.0, refp["cp_l"] * inp.subcooling_k)
        dh_total = dh_desup + dh_cond + dh_sub
        q_total = inp.q_total_kw * 1000
        mdot_ref_auto = q_total / dh_total if dh_total > 0 else float("nan")
        if inp.refrigerant_flow_mode.startswith("Use compressor"):
            mdot_ref = max(0.0, inp.user_mdot_ref_kg_s)
        else:
            mdot_ref = mdot_ref_auto
        q_ref_available = mdot_ref * dh_total if dh_total > 0 else 0.0
        refrigerant_capacity_ok = q_ref_available >= 0.98 * q_total
        q_zone_basis = min(q_total, q_ref_available) if q_ref_available > 0 else 0.0
        # Zone demand is based on the actual refrigerant flow available. If compressor flow is too low,
        # the report now explicitly shows this rather than hiding it as a UA failure.
        q_desup = mdot_ref * dh_desup
        q_cond = mdot_ref * dh_cond
        q_sub = mdot_ref * dh_sub
        t_ref_liq_out_req = inp.t_cond_c - inp.subcooling_k

        # Seawater side
        if getattr(inp, "seawater_flow_mode", "Auto from water ΔT").startswith("Enter") and getattr(inp, "user_vol_sw_m3h", 0.0) > 0:
            vol_w_m3h = float(inp.user_vol_sw_m3h)
            mdot_w = vol_w_m3h * swp["rho"] / 3600.0
            actual_sw_dt = q_total / (mdot_w * swp["cp"]) if mdot_w > 0 else float("nan")
            t_w_out_req = inp.seawater_in_c + actual_sw_dt
        else:
            t_w_out_req = inp.seawater_in_c + inp.seawater_dt_k
            mdot_w = q_total / (swp["cp"] * inp.seawater_dt_k) if inp.seawater_dt_k > 0 else float("nan")
            vol_w_m3h = mdot_w / swp["rho"] * 3600
            actual_sw_dt = inp.seawater_dt_k
        flow_area_tubes = tubes_per_pass * math.pi * effective_di**2 / 4
        v_tube = mdot_w / (swp["rho"] * flow_area_tubes) if flow_area_tubes > 0 else float("nan")
        Re_tube = swp["rho"] * v_tube * effective_di / swp["mu"] if swp["mu"] > 0 else float("nan")
        hi, Nu_i = gnielinski_htc(Re_tube, swp["pr"], swp["k"], effective_di)
        f_tube = friction_factor_churchill_like(Re_tube, rel_rough=1.5e-6 / effective_di)
        # Include U-bend/pass losses as a pragmatic estimate.
        dp_fric = f_tube * (inp.tube_length_m * inp.tube_passes / effective_di) * (swp["rho"] * v_tube**2 / 2)
        dp_minor = (2.0 + 1.5 * inp.tube_passes) * (swp["rho"] * v_tube**2 / 2)
        dp_tube = dp_fric + dp_minor

        # Geometry/shell side
        bundle_d = tube_bundle_diameter(inp.n_tubes, pitch, inp.tube_layout)
        clearance = 0.025 if bundle_d < 0.5 else 0.035
        shell_id = bundle_d + 2 * clearance
        shell_od = shell_id + 2 * (inp.shell_wall_mm / 1000.0)
        baffle_spacing = inp.tube_length_m / (inp.n_baffles + 1)
        baffle_cut = inp.baffle_cut_pct / 100
        # Simplified baffle/window factor. Earlier versions clamped most normal cuts to 0.55,
        # so changing baffle cut had almost no visible effect. This keeps a practical
        # sensitivity: larger baffle cut -> larger window bypass / lower crossflow intensity.
        window_factor = clamp(1.0 - baffle_cut, 0.35, 0.75)
        shell_cross_area = max(1e-5, shell_id * baffle_spacing * (pitch - do) / pitch * window_factor)
        De = max(1e-4, equivalent_shell_diameter(pitch, do, inp.tube_layout))
        # Refrigerant superficial vapor velocity screening at inlet
        v_shell_vapor = mdot_ref / (refp["rho_v"] * shell_cross_area) if shell_cross_area > 0 else float("nan")
        Re_shell_v = refp["rho_v"] * v_shell_vapor * De / refp["mu_v"] if refp["mu_v"] > 0 else float("nan")
        fshell = 0.2 * Re_shell_v ** -0.2 if Re_shell_v and Re_shell_v > 0 else float("nan")
        # Shell-side refrigerant pressure-drop screening.
        # Previous versions showed 0.00 kPa because the calculated value is often
        # very small and was rounded away. This is not a rigorous Bell-Delaware
        # pressure-drop method; it is a conservative screening estimate including
        # repeated cross-flow losses plus a length/equivalent-diameter friction term.
        if fshell == fshell:
            dynamic_head_shell = refp["rho_v"] * v_shell_vapor**2 / 2.0
            crossflow_losses = max(1, inp.n_baffles + 1) * fshell * dynamic_head_shell
            longitudinal_friction = fshell * max(inp.tube_length_m / De, 1.0) * dynamic_head_shell * 0.25
            entrance_exit_loss = 2.0 * dynamic_head_shell
            dp_shell = crossflow_losses + longitudinal_friction + entrance_exit_loss
        else:
            dynamic_head_shell = float("nan")
            dp_shell = float("nan")

        # Allocate area to zones
        if inp.allocation_mode.startswith("Manual"):
            raw = [inp.frac_desuperheat, inp.frac_condense, inp.frac_subcool]
            s = sum(raw) if sum(raw) > 0 else 100
            f_desup, f_cond, f_sub = [x / s for x in raw]
        else:
            # First pass approximate area proportions based on duty and typical U difficulty.
            weights = [q_desup / 600 if q_desup > 0 else 0, q_cond / 1000, q_sub / 450 if q_sub > 0 else 0]
            s = sum(weights) if sum(weights) > 0 else 1
            f_desup, f_cond, f_sub = [w / s for w in weights]
            # Ensure subcool gets a meaningful minimum when required.
            if inp.subcooling_k > 0:
                f_sub = max(f_sub, 0.15)
                rem = 1 - f_sub
                other_sum = f_desup + f_cond
                f_desup = rem * f_desup / other_sum if other_sum > 0 else 0.10
                f_cond = rem * f_cond / other_sum if other_sum > 0 else 0.75
        A_desup, A_cond, A_sub = area_total * f_desup, area_total * f_cond, area_total * f_sub

        # Wall/fouling resistance based on outside-area basis.
        # For GEWA tubes, use catalogue fin root OD and internal ID for the metal path,
        # while U/area are still reported on envelope OD basis.
        wall_do_for_resistance = do
        wall_di_for_resistance = di
        if str(tube_opt.get("type", "")).startswith("GEWA") and tube_opt.get("root_od_mm") and effective_di > 0:
            wall_do_for_resistance = float(tube_opt["root_od_mm"]) / 1000.0
            wall_di_for_resistance = effective_di
        r_wall = do * math.log(max(wall_do_for_resistance, wall_di_for_resistance*1.001) / max(wall_di_for_resistance, 1e-6)) / (2 * k_tube)
        r_foul_i = inp.fouling_seawater * (do / di)
        r_foul_o = inp.fouling_refrigerant
        ao_ai_effective = enhanced_area_per_m / (math.pi * effective_di) if effective_di > 0 else (do / di)
        r_i = (1 / hi) * ao_ai_effective if hi and hi > 0 else float("inf")

        # HTC by zone
        # Estimate wall temp for condensation from coolant average + approach guess.
        t_wall_cond = inp.seawater_in_c + inp.seawater_dt_k * 0.6 + 2.0
        rows_est = max(1, int(math.sqrt(inp.n_tubes)))
        ho_cond_plain, dt_film = shell_condensation_htc_nusselt_horizontal_bundle(refp, do, inp.t_cond_c, t_wall_cond, rows_est)
        h_shell_vap_plain, Nu_vap, Re_shell_vap2, _ = simple_shell_single_phase_htc(mdot_ref, refp["rho_v"], refp["mu_v"], refp["k_v"], refp["cp_v"], shell_cross_area, De)
        h_shell_liq_plain, Nu_liq, Re_shell_liq, v_shell_liq = simple_shell_single_phase_htc(mdot_ref, refp["rho_l"], refp["mu_l"], refp["k_l"], refp["cp_l"], shell_cross_area, De)
        if getattr(inp, "shell_method", "Bell-Delaware screening").startswith("Bell"):
            bcut = inp.baffle_cut_pct
            jc = clamp(1.08 - abs(bcut - 25.0) * 0.012, 0.72, 1.08)
            jl = 0.88
            jb = 0.92
            js = clamp(0.92 + min(inp.n_baffles, 12) * 0.006, 0.92, 1.00)
            crossflow_factor = clamp((max(v_shell_vapor, 0.05) / 0.7) ** 0.12 * (0.55 / max(window_factor, 0.20)) ** 0.10, 0.75, 1.30)
            shell_corr = jc * jl * jb * js * crossflow_factor
            shell_method_note = "Bell-Delaware screening correction applied (Jc/Jl/Jb/Js approximate plus crossflow sensitivity)."
        else:
            shell_corr = 1.0
            shell_method_note = "Simple shell-side screening method."
        if tube_opt["type"] == "custom" or str(getattr(inp, "enhanced_tube_option", "")).startswith("Datang") or str(tube_opt.get("type", "")).startswith("GEWA"):
            cond_mult = float(getattr(inp, "user_enhanced_cond_mult", tube_opt.get("htc_mult_cond", 1.0)))
        else:
            cond_mult = float(tube_opt.get("htc_mult_cond", 1.0))
        des_mult = float(tube_opt.get("htc_mult_desup", 1.0))
        sub_mult = float(tube_opt.get("htc_mult_sub", 1.0))
        ho_cond = ho_cond_plain * shell_corr * cond_mult
        h_shell_vap = h_shell_vap_plain * shell_corr * des_mult if h_shell_vap_plain and h_shell_vap_plain > 0 else h_shell_vap_plain
        h_shell_liq = h_shell_liq_plain * shell_corr * sub_mult if h_shell_liq_plain and h_shell_liq_plain > 0 else h_shell_liq_plain
        U_cond = 1 / (1 / ho_cond + r_foul_o + r_wall + r_foul_i + r_i)
        U_desup = 1 / (1 / h_shell_vap + r_foul_o + r_wall + r_foul_i + r_i) if h_shell_vap and h_shell_vap > 0 else U_cond * 0.5
        U_sub = 1 / (1 / h_shell_liq + r_foul_o + r_wall + r_foul_i + r_i) if h_shell_liq and h_shell_liq > 0 else U_cond * 0.35

        # Sequential zone performance, with subcooler first on cold seawater side for integrated subcooler logic.
        Cw = mdot_w * swp["cp"]
        # Subcool zone: cold seawater first, liquid refrigerant from Tsat to lower temp.
        Cref_sub = mdot_ref * refp["cp_l"]
        Cmin_sub = min(Cw, Cref_sub) if Cref_sub > 0 else Cw
        Cmax_sub = max(Cw, Cref_sub) if Cref_sub > 0 else Cw
        Cr_sub = Cmin_sub / Cmax_sub if Cmax_sub > 0 else 0
        NTU_sub = U_sub * A_sub / Cmin_sub if Cmin_sub > 0 else 0
        eps_sub = self.epsilon_counterflow(NTU_sub, Cr_sub)
        qmax_sub = Cmin_sub * max(0.0, inp.t_cond_c - inp.seawater_in_c)
        q_sub_ach = min(q_sub, eps_sub * qmax_sub)
        t_w_after_sub = inp.seawater_in_c + q_sub_ach / Cw if Cw > 0 else inp.seawater_in_c
        t_ref_liq_out = inp.t_cond_c - q_sub_ach / Cref_sub if Cref_sub > 0 else inp.t_cond_c

        # Condensing zone at nearly constant Tsat.
        NTU_cond = U_cond * A_cond / Cw if Cw > 0 else 0
        eps_cond = 1 - math.exp(-NTU_cond)
        qmax_cond = Cw * max(0.0, inp.t_cond_c - t_w_after_sub)
        q_cond_ach = min(q_cond, eps_cond * qmax_cond)
        t_w_after_cond = t_w_after_sub + q_cond_ach / Cw if Cw > 0 else t_w_after_sub

        # Desuperheat zone: hottest refrigerant can meet warmest water.
        Cref_des = mdot_ref * refp["cp_v"]
        Cmin_des = min(Cw, Cref_des) if Cref_des > 0 else Cw
        Cmax_des = max(Cw, Cref_des) if Cref_des > 0 else Cw
        Cr_des = Cmin_des / Cmax_des if Cmax_des > 0 else 0
        NTU_des = U_desup * A_desup / Cmin_des if Cmin_des > 0 else 0
        eps_des = self.epsilon_counterflow(NTU_des, Cr_des)
        qmax_des = Cmin_des * max(0.0, inp.t_discharge_c - t_w_after_cond)
        q_des_ach = min(q_desup, eps_des * qmax_des)
        t_w_out_ach = t_w_after_cond + q_des_ach / Cw if Cw > 0 else t_w_after_cond
        t_ref_after_des = inp.t_discharge_c - q_des_ach / Cref_des if Cref_des > 0 else inp.t_discharge_c

        # UA/temperature-difference potential by zone. This tells the user whether the shortfall is
        # refrigerant-flow limited, surface-area/UA limited, or zone-allocation limited.
        q_sub_potential = eps_sub * qmax_sub
        q_cond_potential = eps_cond * qmax_cond
        q_des_potential = eps_des * qmax_des
        q_ua_potential = q_sub_potential + q_cond_potential + q_des_potential
        # Theoretical heat transfer possible from terminal temperatures and heat-capacity rates
        # before applying UA/effectiveness. For the condensing zone the refrigerant capacity rate is
        # treated as infinite, therefore Cmin is the seawater side.
        q_cmin_max = qmax_sub + qmax_cond + qmax_des

        q_ach = q_sub_ach + q_cond_ach + q_des_ach
        subcool_ach = max(0.0, inp.t_cond_c - t_ref_liq_out)
        thermal_total_ok = q_ach >= 0.98 * q_total
        subcool_ok = subcool_ach >= 0.95 * inp.subcooling_k
        dp_tube_ok = (dp_tube / 1000) <= inp.max_tube_dp_kpa
        dp_shell_ok = (dp_shell / 1000) <= inp.max_shell_dp_kpa if dp_shell == dp_shell else None
        velocity_ok = inp.min_tube_velocity <= v_tube <= inp.max_tube_velocity
        shell_vel_ok = v_shell_vapor <= inp.max_shell_velocity
        tema = tema_baffle_guidance(shell_id, baffle_spacing, do, inp.tube_material, sw_avg_t)
        tube_hole = tube_hole_guidance(do)

        # Compactness guidance: if the calculated straight tube length is too long for a packaged unit,
        # estimate the tube count and shell diameter required to keep the same outside area at target length.
        package_constraint_enabled = bool(getattr(inp, "package_constraint_enabled", False))
        target_len = max(0.3, inp.max_package_length_m)
        n_tubes_for_target = int(math.ceil(area_total / (math.pi * do * target_len) / max(1, inp.tube_passes)) * max(1, inp.tube_passes))
        bundle_d_target = tube_bundle_diameter(n_tubes_for_target, pitch, inp.tube_layout)
        shell_id_target = bundle_d_target + 2 * clearance if bundle_d_target == bundle_d_target else float("nan")

        # Approximate manufacturing weight estimate for quotation comparison.
        rho_tube = TUBE_MATERIALS[inp.tube_material].get("density", 8900)
        rho_shell = 7850 if "Carbon" in inp.shell_material else 8000
        tube_weight_kg = (enhanced_weight_kg_m * inp.tube_length_m * inp.n_tubes) if enhanced_weight_kg_m else inp.n_tubes * (math.pi/4) * max(do**2 - effective_di**2, 0) * inp.tube_length_m * rho_tube
        shell_weight_kg = math.pi * shell_id * inp.tube_length_m * (inp.shell_wall_mm/1000.0) * rho_shell
        ts_thk = max(0.018, 0.08 * shell_id)  # screening only
        tubesheet_weight_kg = 2 * (math.pi * shell_id**2 / 4) * ts_thk * rho_shell
        baffle_thk = 0.006
        baffle_area = max(math.pi * shell_id**2 / 4 * (1 - baffle_cut), 0)
        baffle_weight_kg = inp.n_baffles * baffle_area * baffle_thk * rho_shell
        waterbox_weight_kg = 0.35 * shell_weight_kg + 0.20 * tubesheet_weight_kg
        supports_nozzles_weight_kg = 0.12 * (tube_weight_kg + shell_weight_kg + tubesheet_weight_kg + baffle_weight_kg + waterbox_weight_kg)
        dry_weight_kg = tube_weight_kg + shell_weight_kg + tubesheet_weight_kg + baffle_weight_kg + waterbox_weight_kg + supports_nozzles_weight_kg
        water_volume_m3 = inp.n_tubes * math.pi * effective_di**2 / 4 * inp.tube_length_m
        water_filled_weight_kg = dry_weight_kg + water_volume_m3 * swp["rho"]

        # Approximate physical zone lengths. For the current model the zones are arranged counter-current:
        # cold seawater first meets subcooler, then condensing, then desuperheating.
        zone_len_des_m = inp.tube_length_m * f_desup
        zone_len_cond_m = inp.tube_length_m * f_cond
        zone_len_sub_m = inp.tube_length_m * f_sub

        # Resistance breakdown: this is the most useful "which side is limiting" insight.
        def resistance_breakdown(h_shell: float) -> Dict[str, float]:
            r_shell = 1 / h_shell if h_shell and h_shell > 0 else float("inf")
            total = r_shell + r_foul_o + r_wall + r_foul_i + r_i
            if not total or total <= 0 or total == float("inf"):
                return {"Shell/refrigerant film": 0, "Seawater tube film": 0, "Seawater fouling": 0, "Refrigerant oil/fouling": 0, "Tube wall": 0}
            return {
                "Shell/refrigerant film": 100 * r_shell / total,
                "Seawater tube film": 100 * r_i / total,
                "Seawater fouling": 100 * r_foul_i / total,
                "Refrigerant oil/fouling": 100 * r_foul_o / total,
                "Tube wall": 100 * r_wall / total,
            }
        rb_cond = resistance_breakdown(ho_cond)
        rb_des = resistance_breakdown(h_shell_vap)
        rb_sub = resistance_breakdown(h_shell_liq)
        limiting_cond = max(rb_cond, key=rb_cond.get)
        limiting_des = max(rb_des, key=rb_des.get)
        limiting_sub = max(rb_sub, key=rb_sub.get)

        # Required areas for insight
        lmtd_sub = safe_log_mean(inp.t_cond_c - inp.seawater_in_c, t_ref_liq_out_req - t_w_after_sub if t_ref_liq_out_req > t_w_after_sub else 0.1)
        a_sub_req = q_sub / (U_sub * max(lmtd_sub, 0.1)) if U_sub > 0 and q_sub > 0 else 0
        lmtd_cond = safe_log_mean(inp.t_cond_c - t_w_after_sub, inp.t_cond_c - t_w_after_cond)
        a_cond_req = q_cond / (U_cond * max(lmtd_cond, 0.1)) if U_cond > 0 else 0
        lmtd_des = safe_log_mean(inp.t_discharge_c - t_w_after_cond, inp.t_cond_c - t_w_out_ach if inp.t_cond_c > t_w_out_ach else 0.1)
        a_des_req = q_desup / (U_desup * max(lmtd_des, 0.1)) if U_desup > 0 and q_desup > 0 else 0

        reasons = {
            "Refrigerant mass flow / enthalpy capacity": refrigerant_capacity_ok,
            "Total heat rejection": thermal_total_ok,
            "Required subcooling": subcool_ok,
            "Tube-side seawater velocity": velocity_ok,
            "Tube-side pressure drop": dp_tube_ok,
            "Shell-side refrigerant pressure drop": dp_shell_ok,
            "Shell-side vapor velocity screening": shell_vel_ok,
            "TEMA minimum baffle spacing screening": tema["min_spacing_ok"],
            "Unsupported span screening": tema["max_span_ok"],
        }
        guidance = self.make_guidance(inp, {
            "thermal_total_ok": thermal_total_ok, "subcool_ok": subcool_ok, "dp_tube_ok": dp_tube_ok,
            "refrigerant_capacity_ok": refrigerant_capacity_ok,
            "velocity_ok": velocity_ok, "shell_vel_ok": shell_vel_ok, "dp_shell_ok": dp_shell_ok,
            "subcool_ach": subcool_ach, "q_ach": q_ach, "q_total": q_total,
            "q_ref_available": q_ref_available, "q_ua_potential": q_ua_potential,
            "v_tube": v_tube, "dp_tube_kpa": dp_tube / 1000, "A_sub": A_sub, "A_sub_req": a_sub_req,
            "A_total": area_total, "v_shell_vapor": v_shell_vapor, "baffle_spacing": baffle_spacing,
            "limiting_cond": limiting_cond, "limiting_des": limiting_des, "limiting_sub": limiting_sub,
            "tube_length_m": inp.tube_length_m, "max_package_length_m": inp.max_package_length_m,
            "package_constraint_enabled": package_constraint_enabled,
            "n_tubes": inp.n_tubes, "n_tubes_for_target": n_tubes_for_target,
            "shell_id_target_mm": shell_id_target * 1000 if shell_id_target == shell_id_target else float("nan"),
        })
        all_ok = all(v is True for v in reasons.values() if v is not None)
        status = "Suitable for preliminary manufacture review" if all_ok else "Needs design revision"

        return {
            "inputs": inp,
            "status": status,
            "water_service": inp.water_service,
            "reasons": reasons,
            "guidance": guidance,
            "ref_props": refp,
            "sw_props": swp,
            "q_total_kw": q_total / 1000, "q_ach_kw": q_ach / 1000,
            "q_ref_available_kw": q_ref_available / 1000, "q_ua_potential_kw": q_ua_potential / 1000,
            "q_cmin_max_kw": q_cmin_max / 1000,
            "overall_effectiveness_cmin": (q_ach / q_cmin_max) if q_cmin_max > 0 else float("nan"),
            "ua_utilization": (q_ach / q_ua_potential) if q_ua_potential > 0 else float("nan"),
            "qmax_sub_kw": qmax_sub / 1000, "qmax_cond_kw": qmax_cond / 1000, "qmax_des_kw": qmax_des / 1000,
            "q_sub_potential_kw": q_sub_potential / 1000, "q_cond_potential_kw": q_cond_potential / 1000, "q_des_potential_kw": q_des_potential / 1000,
            "mdot_ref_auto_kg_s": mdot_ref_auto,
            "q_desup_req_kw": q_desup / 1000, "q_cond_req_kw": q_cond / 1000, "q_sub_req_kw": q_sub / 1000,
            "q_desup_ach_kw": q_des_ach / 1000, "q_cond_ach_kw": q_cond_ach / 1000, "q_sub_ach_kw": q_sub_ach / 1000,
            "subcool_req_k": inp.subcooling_k, "subcool_ach_k": subcool_ach,
            "mdot_ref_kg_s": mdot_ref, "mdot_ref_kg_hr": mdot_ref * 3600,
            "mdot_sw_kg_s": mdot_w, "vol_sw_m3h": vol_w_m3h, "actual_sw_dt_k": actual_sw_dt,
            "seawater_flow_mode": getattr(inp, "seawater_flow_mode", "Auto from water ΔT"),
            "t_sw_in_c": inp.seawater_in_c, "t_sw_out_req_c": t_w_out_req, "t_sw_out_ach_c": t_w_out_ach,
            "t_ref_discharge_c": inp.t_discharge_c, "t_ref_cond_c": inp.t_cond_c, "t_ref_liq_out_c": t_ref_liq_out,
            "t_ref_liq_out_req_c": t_ref_liq_out_req, "t_ref_after_des_c": t_ref_after_des,
            "Cw_kwK": Cw / 1000, "Cref_des_kwK": Cref_des / 1000, "Cref_sub_kwK": Cref_sub / 1000,
            "Cmin_des_kwK": Cmin_des / 1000, "Cmax_des_kwK": Cmax_des / 1000,
            "Cmin_sub_kwK": Cmin_sub / 1000, "Cmax_sub_kwK": Cmax_sub / 1000,
            "do_mm": do * 1000, "di_mm": effective_di * 1000, "plain_di_mm": di * 1000, "wall_mm": wall * 1000, "pitch_mm": pitch * 1000,
            "n_tubes": inp.n_tubes, "tubes_per_pass": tubes_per_pass, "passes": inp.tube_passes,
            "tube_length_m": inp.tube_length_m, "area_total_m2": area_total, "plain_area_total_m2": plain_area_total, "area_enhancement_ratio": area_enhancement_ratio, "enhanced_area_per_m_m2": enhanced_area_per_m,
            "A_desup_m2": A_desup, "A_cond_m2": A_cond, "A_sub_m2": A_sub,
            "A_des_req_m2": a_des_req, "A_cond_req_m2": a_cond_req, "A_sub_req_m2": a_sub_req,
            "bundle_diameter_mm": bundle_d * 1000, "shell_id_mm": shell_id * 1000, "shell_od_mm": shell_od * 1000, "shell_wall_mm": inp.shell_wall_mm, "shell_clearance_radial_mm": clearance * 1000,
            "max_package_length_m": inp.max_package_length_m, "package_constraint_enabled": package_constraint_enabled, "n_tubes_for_target_length": n_tubes_for_target,
            "shell_id_for_target_length_mm": shell_id_target * 1000 if shell_id_target == shell_id_target else float("nan"),
            "length_compact_ratio": inp.tube_length_m / target_len if target_len > 0 else float("nan"),
            "baffle_spacing_mm": baffle_spacing * 1000, "baffle_cut_pct": inp.baffle_cut_pct, "window_factor": window_factor, "baffle_thermal_factor": shell_corr, "shell_cross_area_m2": shell_cross_area,
            "Nu_i": Nu_i, "Re_i": Re_tube, "Pr_i": swp["pr"], "f_i": f_tube,
            "hi_w_m2k": hi, "h_shell_desup_m2k": h_shell_vap, "ho_cond_m2k": ho_cond, "h_shell_sub_m2k": h_shell_liq, "ho_cond_plain_m2k": ho_cond_plain, "shell_correction_factor": shell_corr, "shell_method_note": shell_method_note,
            "U_cond_m2k": U_cond, "U_desup_m2k": U_desup, "U_sub_m2k": U_sub,
            "Re_shell_v": Re_shell_v, "v_shell_vapor_ms": v_shell_vapor, "v_shell_liq_ms": v_shell_liq,
            "Re_shell_liq": Re_shell_liq, "Nu_shell_liq": Nu_liq,
            "v_tube_ms": v_tube, "dp_tube_kpa": dp_tube / 1000, "dp_shell_kpa": dp_shell / 1000, "dp_shell_pa": dp_shell,
            "NTU_sub": NTU_sub, "eps_sub": eps_sub, "Cr_sub": Cr_sub,
            "NTU_cond": NTU_cond, "eps_cond": eps_cond,
            "NTU_des": NTU_des, "eps_des": eps_des, "Cr_des": Cr_des,
            "lmtd_sub_c": lmtd_sub, "lmtd_cond_c": lmtd_cond, "lmtd_des_c": lmtd_des,
            "rb_cond": rb_cond, "rb_des": rb_des, "rb_sub": rb_sub,
            "limiting_cond": limiting_cond, "limiting_des": limiting_des, "limiting_sub": limiting_sub,
            "specific_capacity_kw_m2": q_ach / 1000 / area_total if area_total > 0 else float("nan"),
            "zone_len_des_m": zone_len_des_m, "zone_len_cond_m": zone_len_cond_m, "zone_len_sub_m": zone_len_sub_m,
            "tube_weight_kg": tube_weight_kg, "shell_weight_kg": shell_weight_kg, "tubesheet_weight_kg": tubesheet_weight_kg, "baffle_weight_kg": baffle_weight_kg, "waterbox_weight_kg": waterbox_weight_kg, "supports_nozzles_weight_kg": supports_nozzles_weight_kg, "dry_weight_kg": dry_weight_kg, "water_filled_weight_kg": water_filled_weight_kg,
            "enhanced_tube_option": getattr(inp, "enhanced_tube_option", "Plain smooth tube"), "enhanced_tube_note": tube_opt.get("note", ""), "enhanced_tube_source": tube_opt.get("source", ""),
            "enhanced_fpi": getattr(inp, "enhanced_fpi", 0.0), "enhanced_fin_height_mm": getattr(inp, "enhanced_fin_height_mm", 0.0), "enhanced_fin_thickness_mm": getattr(inp, "enhanced_fin_thickness_mm", 0.0), "enhanced_cond_mult_used": cond_mult,
            "tema": tema, "tube_hole": tube_hole,
            "safe_limits": {
                "Minimum tube velocity m/s": inp.min_tube_velocity,
                "Maximum tube velocity m/s": inp.max_tube_velocity,
                "Maximum tube-side pressure drop kPa": inp.max_tube_dp_kpa,
                "Maximum shell-side pressure drop kPa": inp.max_shell_dp_kpa,
                "Maximum shell vapor velocity m/s": inp.max_shell_velocity,
            },
        }

    @staticmethod
    def epsilon_counterflow(NTU: float, Cr: float) -> float:
        if NTU <= 0:
            return 0.0
        if Cr < 1e-9:
            return 1 - math.exp(-NTU)
        if abs(1 - Cr) < 1e-9:
            return NTU / (1 + NTU)
        return (1 - math.exp(-NTU * (1 - Cr))) / (1 - Cr * math.exp(-NTU * (1 - Cr)))

    @staticmethod
    def make_guidance(inp: CondenserInputs, r: Dict[str, float]) -> List[str]:
        g: List[str] = []
        if not r.get("refrigerant_capacity_ok", True):
            g.append(f"Refrigerant flow is insufficient for the selected heat rejection. Available refrigerant enthalpy capacity is {r['q_ref_available']/1000:.2f} kW vs required {r['q_total']/1000:.2f} kW. Increase compressor refrigerant mass flow, reduce selected duty, or check condensing/subcooling assumptions.")
        if not r["subcool_ok"]:
            g.append(f"Subcooling shortfall: achieved {r['subcool_ach']:.2f} K. Increase subcool area fraction/tube length/tube count, lower seawater inlet temperature, or increase seawater flow. Required subcool area estimate is {r['A_sub_req']:.2f} m² vs allocated {r['A_sub']:.2f} m².")
            if r["A_sub_req"] > r["A_sub"] * 1.1:
                g.append("Use manual area allocation and increase subcooler area fraction. Place subcooler at the cold seawater entry end of the bundle.")
        if not r["thermal_total_ok"]:
            if r.get("q_ua_potential", 0) < 0.98 * r.get("q_total", 0):
                g.append(f"Total heat rejection is UA/temperature-difference limited. Maximum UA-based potential is about {r['q_ua_potential']/1000:.2f} kW vs required {r['q_total']/1000:.2f} kW. Increase tube length/tube count, reduce fouling allowance, increase condensing temperature, or lower seawater inlet temperature.")
            else:
                g.append("Total heat rejection is low mainly due to zone allocation. Shift more area to the deficient zone(s), especially desuperheating/condensing, rather than only increasing total area.")
            g.append(f"Dominant resistance: condensing zone = {r.get('limiting_cond','N/A')}, desuperheat zone = {r.get('limiting_des','N/A')}, subcool zone = {r.get('limiting_sub','N/A')}.")
        if r.get("package_constraint_enabled", False) and r.get("tube_length_m", 0) > r.get("max_package_length_m", 999) * 1.05:
            g.append(f"Package length concern: calculated tube length is {r['tube_length_m']:.2f} m, above your target {r['max_package_length_m']:.2f} m. To keep the same area near the target length, estimate about {int(r['n_tubes_for_target'])} tubes instead of {int(r['n_tubes'])}, with an estimated shell ID around {r['shell_id_target_mm']:.0f} mm. Shorter package designs usually need more tubes/larger shell ID, smaller OD tubes with more count, or two parallel condenser circuits.")
        if not r["velocity_ok"]:
            if r["v_tube"] > inp.max_tube_velocity:
                g.append("Tube velocity is high. Reduce tube passes, increase number of tubes, choose a larger tube OD, or increase allowable seawater ΔT to reduce flow.")
            else:
                g.append("Tube velocity is low. Increase tube passes or reduce tube count to improve seawater-side heat transfer, while checking ΔP.")
        if not r["dp_tube_ok"]:
            g.append("Tube-side ΔP is above limit. Reduce passes, increase tube ID, increase tube count, shorten tube length, or split into parallel shells.")
        if not r["shell_vel_ok"]:
            g.append("Shell-side refrigerant vapor velocity is high. Increase shell ID/bundle diameter, reduce baffle restriction, or use more shell flow area.")
        if r["dp_shell_ok"] is False:
            g.append("Shell-side refrigerant ΔP is high. Increase shell diameter, reduce baffle count, increase baffle cut, or reduce refrigerant mass flux.")
        elif r.get("dp_shell_pa", 0) < 10:
            g.append("Shell-side refrigerant ΔP is very small; if it appears as 0.00 kPa on screen, it is a rounding issue. The app now reports small shell-side drops in Pa as well as kPa.")
        if getattr(inp, "enhanced_tube_option", "Plain smooth tube") != "Plain smooth tube":
            g.append("Enhanced tube option selected: verify supplier rating, finned/land lengths at baffles and tube sheets, expansion procedure, cleaning method, and allowable seawater velocity before manufacture.")
        if not g:
            g.append("Design screening is acceptable. Next step: mechanical pressure design, nozzle sizing, vibration check, manufacturing drawing and certified code review.")
        return g


# =============================================================================
# PDF REPORT
# =============================================================================

def make_pdf_report(results: Dict[str, object]) -> Optional[bytes]:
    if not REPORTLAB_AVAILABLE:
        return None
    buf = BytesIO()
    doc = SimpleDocTemplate(buf, pagesize=landscape(A4), rightMargin=12*mm, leftMargin=12*mm, topMargin=10*mm, bottomMargin=10*mm)
    styles = getSampleStyleSheet()
    title = ParagraphStyle("TitleBlue", parent=styles["Title"], textColor=colors.HexColor("#1E3A8A"), fontSize=16)
    h = ParagraphStyle("Head", parent=styles["Heading2"], textColor=colors.HexColor("#1E3A8A"), fontSize=11)
    small = ParagraphStyle("Small", parent=styles["BodyText"], fontSize=8)
    story = []
    story.append(Paragraph("Seawater-Cooled Freon Shell & Tube Condenser Engineering Report", title))
    story.append(Paragraph(f"Generated: {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}", small))
    story.append(Spacer(1, 4*mm))
    story.append(Paragraph(f"Design Status: <b>{results['status']}</b>", h))
    inp: CondenserInputs = results["inputs"]
    summary = [
        ["Item", "Value", "Unit", "Item", "Value", "Unit"],
        ["Refrigerant", inp.refrigerant, "", "Tube material", inp.tube_material, ""],
        ["Heat rejection required", f"{results['q_total_kw']:.2f}", "kW", "Heat rejection achieved", f"{results['q_ach_kw']:.2f}", "kW"],
        ["Subcooling required", f"{results['subcool_req_k']:.2f}", "K", "Subcooling achieved", f"{results['subcool_ach_k']:.2f}", "K"],
        ["Seawater in/out", f"{results['t_sw_in_c']:.1f}/{results['t_sw_out_ach_c']:.1f}", "°C", "Refrigerant out", f"{results['t_ref_liq_out_c']:.1f}", "°C"],
        ["Tube count / passes", f"{results['n_tubes']} / {results['passes']}", "", "Tube length", f"{results['tube_length_m']:.2f}", "m"],
        ["Shell ID / OD", f"{results['shell_id_mm']:.1f} / {results['shell_od_mm']:.1f}", "mm", "Bundle diameter", f"{results['bundle_diameter_mm']:.1f}", "mm"],
        ["Cmin theoretical Qmax", f"{results['q_cmin_max_kw']:.2f}", "kW", "Overall effectiveness", f"{results['overall_effectiveness_cmin']:.3f}", "-"],
        ["UA/effectiveness potential", f"{results['q_ua_potential_kw']:.2f}", "kW", "Refrigerant enthalpy capacity", f"{results['q_ref_available_kw']:.2f}", "kW"],
        ["Total area", f"{results['area_total_m2']:.2f}", "m²", "Specific capacity", f"{results['specific_capacity_kw_m2']:.2f}", "kW/m²"],
        ["Enhanced tube", str(results.get("enhanced_tube_option", "Plain"))[:28], "", "Area ratio", f"{results.get('area_enhancement_ratio',1):.2f}", "-"],
        ["Dry weight est.", f"{results.get('dry_weight_kg',0):.0f}", "kg", "Water-filled weight", f"{results.get('water_filled_weight_kg',0):.0f}", "kg"],
        ["Tube velocity", f"{results['v_tube_ms']:.2f}", "m/s", "Tube ΔP", f"{results['dp_tube_kpa']:.1f}", "kPa"],
        ["Shell vapor velocity", f"{results['v_shell_vapor_ms']:.3f}", "m/s", "Shell refrigerant ΔP", format_pressure_drop(results['dp_shell_pa']), ""],
    ]
    t = Table(summary, colWidths=[40*mm, 38*mm, 16*mm, 40*mm, 38*mm, 16*mm])
    t.setStyle(TableStyle([("BACKGROUND", (0,0), (-1,0), colors.HexColor("#1E3A8A")), ("TEXTCOLOR", (0,0), (-1,0), colors.white), ("GRID", (0,0), (-1,-1), 0.25, colors.grey), ("FONT", (0,0), (-1,-1), "Helvetica", 7)]))
    story.append(t)
    story.append(Spacer(1, 4*mm))

    story.append(Paragraph("Zone Performance", h))
    zone = [
        ["Zone", "Required kW", "Achieved kW", "Qmax Cmin kW", "UA potential kW", "Area alloc. m²", "Area req. m²", "U", "NTU", "Eff."],
        ["Desuperheat", f"{results['q_desup_req_kw']:.2f}", f"{results['q_desup_ach_kw']:.2f}", f"{results['qmax_des_kw']:.2f}", f"{results['q_des_potential_kw']:.2f}", f"{results['A_desup_m2']:.2f}", f"{results['A_des_req_m2']:.2f}", f"{results['U_desup_m2k']:.0f}", f"{results['NTU_des']:.2f}", f"{results['eps_des']:.3f}"],
        ["Condense", f"{results['q_cond_req_kw']:.2f}", f"{results['q_cond_ach_kw']:.2f}", f"{results['qmax_cond_kw']:.2f}", f"{results['q_cond_potential_kw']:.2f}", f"{results['A_cond_m2']:.2f}", f"{results['A_cond_req_m2']:.2f}", f"{results['U_cond_m2k']:.0f}", f"{results['NTU_cond']:.2f}", f"{results['eps_cond']:.3f}"],
        ["Subcool", f"{results['q_sub_req_kw']:.2f}", f"{results['q_sub_ach_kw']:.2f}", f"{results['qmax_sub_kw']:.2f}", f"{results['q_sub_potential_kw']:.2f}", f"{results['A_sub_m2']:.2f}", f"{results['A_sub_req_m2']:.2f}", f"{results['U_sub_m2k']:.0f}", f"{results['NTU_sub']:.2f}", f"{results['eps_sub']:.3f}"],
    ]
    zt = Table(zone, colWidths=[27*mm, 23*mm, 23*mm, 24*mm, 25*mm, 23*mm, 24*mm, 14*mm, 14*mm, 14*mm])
    zt.setStyle(TableStyle([("BACKGROUND", (0,0), (-1,0), colors.HexColor("#4B5563")), ("TEXTCOLOR", (0,0), (-1,0), colors.white), ("GRID", (0,0), (-1,-1), 0.25, colors.grey), ("FONT", (0,0), (-1,-1), "Helvetica", 7)]))
    story.append(zt)
    story.append(Spacer(1, 4*mm))

    story.append(Paragraph("Heat-Transfer Coefficients", h))
    htcrows = [["Zone", "Shell/refrig HTC W/m²K", "Tube/seawater HTC W/m²K", "Overall U W/m²K", "Dominant resistance"],
        ["Desuperheat", f"{results['h_shell_desup_m2k']:.0f}", f"{results['hi_w_m2k']:.0f}", f"{results['U_desup_m2k']:.0f}", results["limiting_des"]],
        ["Condense", f"{results['ho_cond_m2k']:.0f}", f"{results['hi_w_m2k']:.0f}", f"{results['U_cond_m2k']:.0f}", results["limiting_cond"]],
        ["Subcool", f"{results['h_shell_sub_m2k']:.0f}", f"{results['hi_w_m2k']:.0f}", f"{results['U_sub_m2k']:.0f}", results["limiting_sub"]],
    ]
    ht = Table(htcrows, colWidths=[32*mm, 42*mm, 42*mm, 30*mm, 58*mm])
    ht.setStyle(TableStyle([("BACKGROUND", (0,0), (-1,0), colors.HexColor("#4B5563")), ("TEXTCOLOR", (0,0), (-1,0), colors.white), ("GRID", (0,0), (-1,-1), 0.25, colors.grey), ("FONT", (0,0), (-1,-1), "Helvetica", 7)]))
    story.append(ht)
    story.append(Spacer(1, 4*mm))

    story.append(Paragraph("Limiting Heat-Transfer Resistance", h))
    limrows = [["Zone", "Dominant Resistance", "Refrig/Shell Film %", "Seawater Film %", "Seawater Fouling %", "Tube Wall %"],
        ["Desuperheat", results["limiting_des"], f"{results['rb_des']['Shell/refrigerant film']:.1f}", f"{results['rb_des']['Seawater tube film']:.1f}", f"{results['rb_des']['Seawater fouling']:.1f}", f"{results['rb_des']['Tube wall']:.1f}"],
        ["Condense", results["limiting_cond"], f"{results['rb_cond']['Shell/refrigerant film']:.1f}", f"{results['rb_cond']['Seawater tube film']:.1f}", f"{results['rb_cond']['Seawater fouling']:.1f}", f"{results['rb_cond']['Tube wall']:.1f}"],
        ["Subcool", results["limiting_sub"], f"{results['rb_sub']['Shell/refrigerant film']:.1f}", f"{results['rb_sub']['Seawater tube film']:.1f}", f"{results['rb_sub']['Seawater fouling']:.1f}", f"{results['rb_sub']['Tube wall']:.1f}"],
    ]
    lt = Table(limrows, colWidths=[32*mm, 55*mm, 30*mm, 30*mm, 33*mm, 25*mm])
    lt.setStyle(TableStyle([("BACKGROUND", (0,0), (-1,0), colors.HexColor("#4B5563")), ("TEXTCOLOR", (0,0), (-1,0), colors.white), ("GRID", (0,0), (-1,-1), 0.25, colors.grey), ("FONT", (0,0), (-1,-1), "Helvetica", 7)]))
    story.append(lt)
    story.append(Spacer(1, 4*mm))

    if results.get("package_constraint_enabled", False):
        story.append(Paragraph("Compact Package Guidance", h))
        compactrows = [["Item", "Value", "Unit"],
            ["Available package straight-tube length", f"{results['max_package_length_m']:.2f}", "m"],
            ["Current/effective tube length", f"{results['tube_length_m']:.2f}", "m"],
            ["Estimated tubes needed at package length", f"{results['n_tubes_for_target_length']}", "tubes"],
            ["Estimated shell ID at package length", f"{results['shell_id_for_target_length_mm']:.0f}", "mm"],
        ]
        cp = Table(compactrows, colWidths=[70*mm, 35*mm, 25*mm])
        cp.setStyle(TableStyle([("BACKGROUND", (0,0), (-1,0), colors.HexColor("#4B5563")), ("TEXTCOLOR", (0,0), (-1,0), colors.white), ("GRID", (0,0), (-1,-1), 0.25, colors.grey), ("FONT", (0,0), (-1,-1), "Helvetica", 7)]))
        story.append(cp)
        story.append(Spacer(1, 4*mm))

    story.append(Paragraph("Catalogue Benchmark (nearest standard models)", h))
    try:
        matches_pdf = catalogue_matches(results, top_n=6)
        if not matches_pdf.empty:
            cat_rows = [["Source", "Model", "Catalog kW", "Adj. kW", "Margin %", "Shell OD", "Length", "Verdict"]]
            for _, row in matches_pdf.iterrows():
                cat_rows.append([
                    str(row["Source"]), str(row["Model"]), f"{row['Catalog kW']:.1f}", f"{row['Adjusted kW est.']:.1f}",
                    f"{row['Margin %']:.1f}", f"{row['Shell OD mm']:.0f}", f"{row['Length mm']:.0f}", str(row["Benchmark verdict"])
                ])
            cat_table = Table(cat_rows, colWidths=[34*mm, 28*mm, 22*mm, 22*mm, 20*mm, 20*mm, 20*mm, 45*mm])
            cat_table.setStyle(TableStyle([("BACKGROUND", (0,0), (-1,0), colors.HexColor("#4B5563")), ("TEXTCOLOR", (0,0), (-1,0), colors.white), ("GRID", (0,0), (-1,-1), 0.25, colors.grey), ("FONT", (0,0), (-1,-1), "Helvetica", 6)]))
            story.append(cat_table)
            story.append(Paragraph("Catalogue benchmark is approximate and uses manual rows from manufacturer catalogues with simple LMTD/fouling/service derating. Confirm final selection in manufacturer software.", small))
            story.append(Spacer(1, 4*mm))
    except Exception as e:
        story.append(Paragraph(f"Catalogue benchmark unavailable: {e}", small))
        story.append(Spacer(1, 4*mm))

    story.append(Paragraph("Design Checks", h))
    checks = [["Check", "Status"]] + [[k, format_status(v)] for k, v in results["reasons"].items()]
    ct = Table(checks, colWidths=[90*mm, 35*mm])
    ct.setStyle(TableStyle([("BACKGROUND", (0,0), (-1,0), colors.HexColor("#1E3A8A")), ("TEXTCOLOR", (0,0), (-1,0), colors.white), ("GRID", (0,0), (-1,-1), 0.25, colors.grey), ("FONT", (0,0), (-1,-1), "Helvetica", 7)]))
    story.append(ct)
    story.append(Spacer(1, 4*mm))
    story.append(Paragraph("Actionable Guidance", h))
    for item in results["guidance"]:
        story.append(Paragraph("• " + item, small))
    story.append(Spacer(1, 3*mm))
    story.append(Paragraph("Disclaimer: thermal/mechanical screening only. Final design must be verified against ASME/TEMA/project standards by a qualified engineer before manufacture.", small))
    doc.build(story)
    data = buf.getvalue()
    buf.close()
    return data


