def check_password() -> bool:
    def entered():
        if st.session_state.get("password") == APP_PASSWORD:
            st.session_state["password_ok"] = True
            st.session_state.pop("password", None)
        else:
            st.session_state["password_ok"] = False
    if "password_ok" not in st.session_state:
        st.text_input("Enter password", type="password", on_change=entered, key="password")
        st.caption("Protected engineering tool")
        return False
    if not st.session_state["password_ok"]:
        st.text_input("Enter password", type="password", on_change=entered, key="password")
        st.error("Password incorrect")
        return False
    return True


def sidebar_inputs() -> CondenserInputs:
    st.sidebar.header("1) Duty & Refrigerant")
    q_total_kw = st.sidebar.number_input("Total condenser heat rejection (kW)", 5.0, 5000.0, 42.2, 1.0)
    refrigerant = st.sidebar.selectbox("Refrigerant", REFRIGERANTS, index=REFRIGERANTS.index("R134a"))
    refrigerant_flow_mode = st.sidebar.radio("Refrigerant mass flow", ["Auto from heat rejection", "Use compressor mass flow"], help="Use compressor mass flow when you already know refrigerant flow from compressor selection.")
    user_mdot_ref_kg_s = st.sidebar.number_input("Compressor refrigerant mass flow (kg/s)", 0.0, 100.0, 0.22, 0.01, disabled=refrigerant_flow_mode.startswith("Auto"))
    t_discharge_c = st.sidebar.number_input("Compressor discharge / superheated vapor inlet (°C)", 30.0, 140.0, 95.0, 1.0)
    t_cond_c = st.sidebar.number_input("Condensing saturation temperature (°C)", 25.0, 80.0, 51.0, 0.5)
    subcooling_k = st.sidebar.number_input("Required liquid subcooling (K)", 0.0, 20.0, 5.0, 0.5)

    st.sidebar.header("2) Cooling Water Side")
    water_service = st.sidebar.selectbox("Cooling water type", WATER_SERVICES, index=0, help="Select Sea water for direct marine/district-cooling seawater. Select Plain/fresh water for cooling tower water, fresh water or closed condenser water.")
    is_seawater = water_service.startswith("Sea")
    water_label = "Seawater" if is_seawater else "Cooling water"
    seawater_in_c = st.sidebar.number_input(f"{water_label} inlet temperature (°C)", 0.0, 45.0, 37.0 if is_seawater else 30.0, 0.5)
    seawater_flow_mode = st.sidebar.radio(f"{water_label} flow basis", ["Auto from water ΔT", "Enter water flow m³/h"], help="Auto mode calculates flow from heat rejection and selected water temperature rise. Entered-flow mode lets you match catalogue flows.")
    if seawater_flow_mode.startswith("Auto"):
        seawater_dt_k = st.sidebar.number_input(f"Target {water_label.lower()} temperature rise ΔT (K)", 1.0, 12.0, 5.0, 0.5)
        user_vol_sw_m3h = 0.0
    else:
        user_vol_sw_m3h = st.sidebar.number_input(f"Entered {water_label.lower()} volume flow (m³/h)", 0.1, 1000.0, 13.0, 0.1)
        seawater_dt_k = st.sidebar.number_input(f"Expected/initial {water_label.lower()} ΔT for property estimate (K)", 1.0, 12.0, 5.0, 0.5)
    salinity_default = 35.0 if is_seawater else 0.0
    salinity_gkg = st.sidebar.number_input("Salinity (g/kg)", 0.0, 45.0, salinity_default, 1.0, help="Use about 35 g/kg for seawater and 0 for plain/fresh water.")
    fouling_default = 0.00024 if is_seawater else 0.000086
    fouling_seawater = st.sidebar.number_input(f"{water_label} fouling resistance (m²·K/W)", 0.0, 0.002, fouling_default, 0.00001, format="%.5f")
    fouling_refrigerant = st.sidebar.number_input("Refrigerant-side fouling/oil film (m²·K/W)", 0.0, 0.001, 0.00004, 0.00001, format="%.5f")

    st.sidebar.header("3) Materials")
    tube_material = st.sidebar.selectbox("Tube material", list(TUBE_MATERIALS.keys()), index=0)
    st.sidebar.caption(TUBE_MATERIALS[tube_material]["note"])
    shell_material = st.sidebar.selectbox("Shell material", list(SHELL_MATERIALS.keys()), index=0)
    tubesheet_material = st.sidebar.selectbox("Tubesheet material", list(TUBESHEET_MATERIALS.keys()), index=0)
    st.sidebar.caption(TUBESHEET_MATERIALS[tubesheet_material])

    st.sidebar.header("4) Tube Bundle Geometry")
    design_mode = st.sidebar.radio("Sizing mode", ["Auto preliminary sizing", "Manual geometry check"], horizontal=False)
    tube_size = st.sidebar.selectbox("Tube OD", list(TUBE_SIZES.keys()), index=2)
    bwg_options = list(TUBE_SIZES[tube_size]["bwg"].keys())
    bwg = st.sidebar.selectbox("Tube BWG / wall", bwg_options, index=min(1, len(bwg_options)-1))
    st.sidebar.header("4A) Enhanced Tube Surface")
    available_enhanced_options = enhanced_options_for_base_tube(tube_material, tube_size, water_service)
    enhanced_tube_option = st.sidebar.selectbox(
        "Surface type for the SAME selected tube",
        available_enhanced_options,
        index=0,
        help="Filtered by the selected Tube Material and Tube OD above. This prevents selecting a 1/2 in Cu-Ni base tube and a 3/4 in titanium enhanced tube at the same time."
    )
    st.sidebar.caption(FINNED_TUBE_OPTIONS[enhanced_tube_option]["note"])
    if enhanced_tube_option == "Plain smooth tube":
        st.sidebar.info("Plain tube selected. Calculations use the material, OD and wall selected in Tube Bundle Geometry.")
    else:
        st.sidebar.success("Enhanced surface will be applied to the SAME base tube selected above.")

    enhanced_fpi = 0.0
    enhanced_fin_height_mm = 0.0
    enhanced_fin_thickness_mm = 0.0
    if str(FINNED_TUBE_OPTIONS[enhanced_tube_option].get("type", "")).startswith("GEWA"):
        selected_gewa = FINNED_TUBE_OPTIONS[enhanced_tube_option]
        user_enhanced_area_m2_m = float(selected_gewa["area_per_m"])
        user_enhanced_weight_kg_m = float(selected_gewa["weight_kg_m"])
        user_enhanced_id_mm = float(selected_gewa["inside_d_mm"])
        default_mult = float(selected_gewa.get("htc_mult_cond", 2.80))
        st.sidebar.caption(
            f"{selected_gewa.get('type', 'GEWA')} uses envelope OD area basis for qo, ho and Uo. "
            f"Geometry used: plain OD {selected_gewa.get('plain_end_od_mm', 0):.2f} mm, fin OD {selected_gewa.get('fin_od_mm', 0):.2f} mm, "
            f"root OD {selected_gewa.get('root_od_mm', 0):.2f} mm, ID {selected_gewa.get('inside_d_mm', 0):.2f} mm, weight {selected_gewa.get('weight_kg_m', 0):.3f} kg/m. "
            "The exact condensation enhancement cannot be calculated from geometry alone, so use the multiplier below and validate with supplier/test data."
        )
        user_enhanced_cond_mult = st.sidebar.number_input(
            "GEWA shell-side condensation film multiplier",
            1.0, 5.0, default_mult, 0.05,
            key=f"gewa_mult_{enhanced_tube_option}_{tube_size}_{bwg}",
            help="This multiplier is applied to the app's plain-tube shell-side condensation HTC. HSTAR benchmark implies a high multiplier, but final value must be confirmed by supplier/test data."
        )
        st.sidebar.success(f"GEWA envelope outside area used = {user_enhanced_area_m2_m:.4f} m²/m; ID used = {user_enhanced_id_mm:.2f} mm; film multiplier = {user_enhanced_cond_mult:.2f}×.")
    elif enhanced_tube_option.startswith("Datang"):
        enhanced_fpi = st.sidebar.selectbox("Low-fin fin density (FPI)", [19.0, 26.0, 28.0, 30.0, 32.0, 35.0, 40.0], index=3, help="Choose the actual fins per inch from the supplier/catalogue. Nippon titanium low-fin uses 30 FPI; Salem/Wolverine catalogues include 19, 26, 28, 32, 35 and 40 FPI families.")
        default_fin_h = 0.82 if enhanced_fpi >= 28 else 1.20
        enhanced_fin_height_mm = st.sidebar.number_input("Low-fin height (mm)", 0.10, 3.00, default_fin_h, 0.05, help="For Nippon titanium low-fin, catalogue fin height is about 0.82 mm. Enter supplier-confirmed value when available.")
        enhanced_fin_thickness_mm = st.sidebar.number_input("Average fin thickness (mm)", 0.05, 1.00, 0.30, 0.01, help="Nippon catalogue gives about 0.3 mm average fin thickness. Use supplier-confirmed value for final design.")
        enh_def = low_fin_defaults_for_selected_tube(tube_material, tube_size, bwg, enhanced_fpi, enhanced_fin_height_mm, enhanced_fin_thickness_mm)
        base_area_default = float(enh_def["area_m2_m"])
        base_id_default = float(enh_def["inside_d_mm"])
        base_weight_default = float(enh_def["weight_kg_m"])
        default_mult = float(FINNED_TUBE_OPTIONS[enhanced_tube_option].get("htc_mult_cond", 1.15))
        st.sidebar.caption(f"Geometry-calculated low-fin area ratio ≈ {enh_def['area_ratio']:.2f}× plain using {enhanced_fpi:.0f} FPI, fin height {enhanced_fin_height_mm:.2f} mm, fin thickness {enhanced_fin_thickness_mm:.2f} mm.")
        user_enhanced_area_m2_m = st.sidebar.number_input(
            "Outside area per metre used (m²/m)", 0.0, 2.0, base_area_default, 0.001, format="%.3f",
            key=f"enh_area_{enhanced_tube_option}_{tube_size}_{bwg}_{enhanced_fpi}",
            help="Default is calculated from FPI/fin height. Override only with supplier-confirmed catalogue area for the same tube."
        )
        user_enhanced_weight_kg_m = st.sidebar.number_input("Tube weight used (kg/m)", 0.0, 20.0, base_weight_default, 0.01, key=f"enh_wt_{enhanced_tube_option}_{tube_size}_{bwg}_{enhanced_fpi}")
        user_enhanced_id_mm = st.sidebar.number_input("Inside diameter used (mm)", 1.0, 100.0, base_id_default, 0.1, key=f"enh_id_{enhanced_tube_option}_{tube_size}_{bwg}_{enhanced_fpi}")
        user_enhanced_cond_mult = st.sidebar.number_input("Extra shell-side condensation film multiplier", 0.8, 3.0, default_mult, 0.05, key=f"enh_mult_{enhanced_tube_option}_{tube_size}_{bwg}_{enhanced_fpi}", help="This is NOT the area ratio. Area increase is already included in outside area. Use this only for extra condensate-drainage/surface effect beyond area; keep 1.0–1.2 unless supplier test data supports more.")
    elif FINNED_TUBE_OPTIONS[enhanced_tube_option]["type"] == "custom":
        enh_def = enhanced_defaults_for_selected_tube(enhanced_tube_option, tube_material, tube_size, bwg)
        base_area_default = float(enh_def["area_m2_m"])
        base_id_default = float(enh_def["inside_d_mm"])
        base_weight_default = float(enh_def["weight_kg_m"])
        default_mult = float(FINNED_TUBE_OPTIONS[enhanced_tube_option].get("htc_mult_cond", 1.00))
        st.sidebar.caption(f"User-defined default for this same tube: area ratio ≈ {enh_def['area_ratio']:.2f}× plain; replace with supplier data.")
        user_enhanced_area_m2_m = st.sidebar.number_input("Actual outside area per metre for selected tube (m²/m)", 0.0, 2.0, base_area_default, 0.001, format="%.3f", key=f"enh_area_{enhanced_tube_option}_{tube_size}_{bwg}")
        user_enhanced_weight_kg_m = st.sidebar.number_input("Actual tube weight for selected tube (kg/m)", 0.0, 20.0, base_weight_default, 0.01, key=f"enh_wt_{enhanced_tube_option}_{tube_size}_{bwg}")
        user_enhanced_id_mm = st.sidebar.number_input("Actual inside diameter for selected tube (mm)", 1.0, 100.0, base_id_default, 0.1, key=f"enh_id_{enhanced_tube_option}_{tube_size}_{bwg}")
        user_enhanced_cond_mult = st.sidebar.number_input("Extra shell-side condensation film multiplier", 0.8, 3.0, default_mult, 0.05, key=f"enh_mult_{enhanced_tube_option}_{tube_size}_{bwg}", help="Area increase is already included separately; this multiplier should represent only additional surface/film enhancement.")
    else:
        user_enhanced_area_m2_m = 0.0
        user_enhanced_weight_kg_m = 0.0
        user_enhanced_id_mm = 0.0
        user_enhanced_cond_mult = 1.0

    # Show exactly what will be used; do not allow a second hidden tube definition.
    selected_opt = FINNED_TUBE_OPTIONS[enhanced_tube_option]
    if enhanced_tube_option != "Plain smooth tube":
        _enh_def_now = low_fin_defaults_for_selected_tube(tube_material, tube_size, bwg, enhanced_fpi, enhanced_fin_height_mm, enhanced_fin_thickness_mm) if enhanced_tube_option.startswith("Datang") else enhanced_defaults_for_selected_tube(enhanced_tube_option, tube_material, tube_size, bwg)
        _used_area = user_enhanced_area_m2_m if (selected_opt.get("area_per_m") is None and user_enhanced_area_m2_m > 0) else _enh_def_now["area_m2_m"]
        _used_mult = user_enhanced_cond_mult if (selected_opt.get('area_per_m') is None or enhanced_tube_option.startswith("Datang") or str(selected_opt.get("type", "")).startswith("GEWA")) else selected_opt.get('htc_mult_cond',1.0)
        st.sidebar.success(f"Thermal calculation will use enhanced outside area ratio ≈ {_used_area / _enh_def_now['plain_area_m2_m']:.2f}× and extra condensation film multiplier {_used_mult:.2f}×.")
    if selected_opt.get("fin_od_mm"):
        st.sidebar.caption(
            f"Catalogue surface data: fin OD/root OD/ID = {selected_opt.get('fin_od_mm'):.2f}/"
            f"{selected_opt.get('root_od_mm'):.2f}/{selected_opt.get('inside_d_mm'):.2f} mm; "
            f"area = {selected_opt.get('area_per_m'):.3f} m²/m; weight = {selected_opt.get('weight_kg_m'):.3f} kg/m."
        )
    if len(available_enhanced_options) == 2 and enhanced_tube_option == "Plain smooth tube":
        st.sidebar.caption("No exact catalogue enhanced option matched this material and OD. Use User-defined enhanced tube if your supplier confirms geometry.")
    shell_method = st.sidebar.selectbox("Shell-side HTC method", ["Bell-Delaware screening correction", "Simple shell-side screening"], index=0)
    tube_layout = st.sidebar.selectbox("Tube layout", TUBE_LAYOUTS)
    pitch_label = st.sidebar.selectbox("Pitch ratio", list(PITCH_RATIOS.keys()), index=0)
    pitch_ratio = PITCH_RATIOS[pitch_label]
    tube_passes = st.sidebar.selectbox("Tube passes", [1, 2, 4, 6, 8], index=2)
    default_tubes = 120
    n_tubes = st.sidebar.number_input("Number of tubes", min_value=8, max_value=5000, value=default_tubes, step=2)
    tube_length_m = st.sidebar.number_input("Tube effective length (m)", 0.5, 12.0, 2.0, 0.1)
    n_baffles = st.sidebar.number_input("Number of baffles", 0, 60, 8, 1)
    baffle_cut_pct = st.sidebar.number_input("Baffle cut (%)", 15.0, 45.0, 25.0, 1.0)
    shell_wall_mm = st.sidebar.number_input("Estimated shell wall thickness (mm)", 3.0, 30.0, 6.0, 0.5, help="For shell OD estimate only. Final pressure thickness must be checked by ASME/TEMA mechanical design.")

    st.sidebar.header("4A) Optional Packaging Constraint")
    package_constraint_enabled = st.sidebar.checkbox(
        "Package constraint study",
        value=False,
        help="Enable only when you want the app to compare the calculated tube length with the maximum straight-tube length available inside your package/unit. This is advisory only; it does not change the heat-transfer calculation."
    )
    if package_constraint_enabled:
        max_package_length_m = st.sidebar.number_input(
            "Available straight-tube length inside package (m)",
            0.3, 6.0, min(float(tube_length_m), 1.50), 0.05,
            help="Used only for compact-package guidance. Example: if your unit can fit only 1.2 m tubes, the app estimates the tube count and shell ID needed to keep the same area."
        )
    else:
        # Keep equal to tube effective length so the compact-package warning is inactive.
        max_package_length_m = float(tube_length_m)

    st.sidebar.header("5) Design Limits")
    material_v_default = TUBE_MATERIALS[tube_material]["max_v_seawater"] if water_service.startswith("Sea") else max(2.5, TUBE_MATERIALS[tube_material]["max_v_seawater"])
    min_tube_velocity = st.sidebar.number_input("Minimum seawater tube velocity (m/s)", 0.1, 3.0, 1.0, 0.1)
    max_tube_velocity = st.sidebar.number_input("Maximum seawater tube velocity (m/s)", 0.5, 5.0, float(material_v_default), 0.1)
    max_tube_dp_kpa = st.sidebar.number_input("Maximum tube-side ΔP (kPa)", 5.0, 300.0, 70.0, 5.0)
    max_shell_dp_kpa = st.sidebar.number_input("Maximum shell-side refrigerant ΔP (kPa)", 1.0, 100.0, 20.0, 1.0)
    max_shell_velocity = st.sidebar.number_input("Max shell vapor superficial velocity (m/s)", 0.5, 25.0, 8.0, 0.5)

    st.sidebar.header("6) Zone Area Allocation")
    allocation_mode = st.sidebar.radio("Area allocation", ["Auto zone allocation", "Manual area fraction"], horizontal=False)
    if allocation_mode.startswith("Manual"):
        st.sidebar.caption("Set desuperheat and subcooling fractions. Condensing fraction is automatically the remaining area, so total is always 100%.")
        frac_desuperheat = st.sidebar.slider("Desuperheat area fraction (%)", 0.0, 40.0, 10.0, 1.0)
        max_sub = max(0.0, 100.0 - frac_desuperheat - 20.0)
        frac_subcool = st.sidebar.slider("Subcooling area fraction (%)", 0.0, float(max_sub), min(20.0, float(max_sub)), 1.0)
        frac_condense = 100.0 - frac_desuperheat - frac_subcool
        st.sidebar.success(f"Condensing area fraction = {frac_condense:.0f}% (auto remainder). Total = 100%.")
    else:
        frac_desuperheat = 10.0
        frac_condense = 70.0
        frac_subcool = 20.0
    auto_margin = st.sidebar.number_input("Auto sizing area safety margin", 1.0, 2.5, 1.20, 0.05)

    return CondenserInputs(q_total_kw, refrigerant, refrigerant_flow_mode, user_mdot_ref_kg_s, t_discharge_c, t_cond_c, subcooling_k,
                           seawater_in_c, seawater_dt_k, water_service, seawater_flow_mode, user_vol_sw_m3h, salinity_gkg, fouling_seawater, fouling_refrigerant,
                           tube_material, enhanced_tube_option, user_enhanced_area_m2_m, user_enhanced_weight_kg_m, user_enhanced_id_mm, user_enhanced_cond_mult, enhanced_fpi, enhanced_fin_height_mm, enhanced_fin_thickness_mm, shell_method, shell_material, tubesheet_material, tube_size, bwg, tube_layout,
                           pitch_ratio, int(tube_passes), float(tube_length_m), int(n_tubes), float(baffle_cut_pct),
                           int(n_baffles), float(shell_wall_mm), float(max_package_length_m), bool(package_constraint_enabled), design_mode, max_tube_velocity, min_tube_velocity,
                           max_tube_dp_kpa, max_shell_dp_kpa, max_shell_velocity,
                           allocation_mode, frac_desuperheat, frac_condense, frac_subcool, auto_margin)


def show_metric_grid(results: Dict[str, object]):
    c1, c2, c3, c4, c5 = st.columns(5)
    c1.metric("Heat rejection achieved", f"{results['q_ach_kw']:.1f} kW", f"Req {results['q_total_kw']:.1f}")
    c2.metric("Cmin/Qmax theoretical", f"{results['q_cmin_max_kw']:.1f} kW", f"ε {results['overall_effectiveness_cmin']:.3f}")
    c3.metric("UA/effectiveness potential", f"{results['q_ua_potential_kw']:.1f} kW", "Max by geometry")
    c4.metric("Refrigerant capacity", f"{results['q_ref_available_kw']:.1f} kW", f"Flow {results['mdot_ref_kg_s']:.3f} kg/s")
    c5.metric("Tube velocity", f"{results['v_tube_ms']:.2f} m/s", f"Limit {results['safe_limits']['Minimum tube velocity m/s']:.1f}-{results['safe_limits']['Maximum tube velocity m/s']:.1f}")

    # Second summary row: keep manufacturing geometry visible without forcing the user
    # to open the Geometry tab.  Users repeatedly compare these values with
    # catalogue shell diameters, so they must be visible in the main screen output.
    g1, g2, g3, g4, g5 = st.columns(5)
    g1.metric("Shell ID", f"{results['shell_id_mm']:.0f} mm")
    g2.metric("Shell OD", f"{results['shell_od_mm']:.0f} mm", f"Wall {results.get('shell_wall_mm', 0):.1f} mm")
    g3.metric("Bundle diameter", f"{results['bundle_diameter_mm']:.0f} mm")
    g4.metric("Tube length", f"{results['tube_length_m']:.2f} m", f"{results['n_tubes']} tubes")
    g5.metric("Dry weight est.", f"{results.get('dry_weight_kg', float('nan')):.0f} kg")



def render_embedded_pdf(pdf_b64: str, height: int = 760) -> None:
    """Render an embedded PDF in Streamlit using an iframe."""
    pdf_display = f'<iframe src="data:application/pdf;base64,{pdf_b64}" width="100%" height="{height}" type="application/pdf"></iframe>'
    st.markdown(pdf_display, unsafe_allow_html=True)


def show_results(results: Dict[str, object]):
    status = results["status"]
    if status.startswith("Suitable"):
        st.success(f"✅ {status}")
    else:
        st.warning(f"⚠️ {status}")
    show_metric_grid(results)

    tab1, tab2, tab3, tab4, tab5, tab6, tab7, tab8, tab9, tab10 = st.tabs(["Design Checks", "Thermal Zones", "Limiting Side", "Geometry", "Hydraulics", "Properties", "Catalogue Benchmark", "Wieland Catalogue", "Weight", "PDF Report"])

    with tab1:
        st.subheader("Design adequacy reasons")
        df = pd.DataFrame([{"Check": k, "Status": format_status(v)} for k, v in results["reasons"].items()])
        st.dataframe(df, hide_index=True, width="stretch")
        st.subheader("Main manufacturing dimensions")
        mfg = pd.DataFrame([
            ["Shell ID", f"{results['shell_id_mm']:.1f}", "mm"],
            ["Shell OD", f"{results['shell_od_mm']:.1f}", "mm"],
            ["Bundle diameter", f"{results['bundle_diameter_mm']:.1f}", "mm"],
            ["Tube effective length", f"{results['tube_length_m']:.2f}", "m"],
            ["Tube count / passes", f"{results['n_tubes']} / {results['passes']}", ""],
            ["Cooling water type", f"{results.get('water_service', 'N/A')}", ""],
            ["Estimated dry weight", f"{results.get('dry_weight_kg', float('nan')):.1f}", "kg"],
        ], columns=["Dimension", "Value", "Unit"])
        st.dataframe(mfg, hide_index=True, width="stretch")
        st.subheader("Actionable design guidance")
        for g in results["guidance"]:
            st.info(g)

    with tab2:
        zone = pd.DataFrame([
            {"Zone": "Desuperheat", "Required kW": results["q_desup_req_kw"], "Achieved kW": results["q_desup_ach_kw"], "Qmax by Cmin kW": results["qmax_des_kw"], "UA potential kW": results["q_des_potential_kw"], "Allocated Area m²": results["A_desup_m2"], "Req. Area Est. m²": results["A_des_req_m2"], "U W/m²K": results["U_desup_m2k"], "NTU": results["NTU_des"], "Effectiveness": results["eps_des"], "Cr": results["Cr_des"]},
            {"Zone": "Condensing", "Required kW": results["q_cond_req_kw"], "Achieved kW": results["q_cond_ach_kw"], "Qmax by Cmin kW": results["qmax_cond_kw"], "UA potential kW": results["q_cond_potential_kw"], "Allocated Area m²": results["A_cond_m2"], "Req. Area Est. m²": results["A_cond_req_m2"], "U W/m²K": results["U_cond_m2k"], "NTU": results["NTU_cond"], "Effectiveness": results["eps_cond"], "Cr": 0.0},
            {"Zone": "Subcooling", "Required kW": results["q_sub_req_kw"], "Achieved kW": results["q_sub_ach_kw"], "Qmax by Cmin kW": results["qmax_sub_kw"], "UA potential kW": results["q_sub_potential_kw"], "Allocated Area m²": results["A_sub_m2"], "Req. Area Est. m²": results["A_sub_req_m2"], "U W/m²K": results["U_sub_m2k"], "NTU": results["NTU_sub"], "Effectiveness": results["eps_sub"], "Cr": results["Cr_sub"]},
        ])
        st.dataframe(zone.style.format({c: "{:.3f}" for c in zone.columns if c != "Zone"}), hide_index=True, width="stretch")
        cap = pd.DataFrame([
            ["Seawater Cw", f"{results['Cw_kwK']:.3f}", "kW/K"],
            ["Desuperheat refrigerant Cref", f"{results['Cref_des_kwK']:.3f}", "kW/K"],
            ["Subcool liquid refrigerant Cref", f"{results['Cref_sub_kwK']:.3f}", "kW/K"],
            ["Theoretical Qmax from Cmin/terminal temperatures", f"{results['q_cmin_max_kw']:.2f}", "kW"],
            ["Overall effectiveness vs Cmin Qmax", f"{results['overall_effectiveness_cmin']:.3f}", "-"],
            ["Geometry/UA potential", f"{results['q_ua_potential_kw']:.2f}", "kW"],
        ], columns=["Capacity / effectiveness item", "Value", "Unit"])
        st.subheader("Heat-capacity and maximum heat-transfer insight")
        st.dataframe(cap, hide_index=True, width="stretch")
        c1, c2, c3 = st.columns(3)
        c1.metric("Seawater in/out achieved", f"{results['t_sw_in_c']:.1f} / {results['t_sw_out_ach_c']:.1f} °C")
        c2.metric("Refrigerant discharge/cond", f"{results['t_ref_discharge_c']:.1f} / {results['t_ref_cond_c']:.1f} °C")
        c3.metric("Liquid outlet", f"{results['t_ref_liq_out_c']:.1f} °C", f"Req {results['t_ref_liq_out_req_c']:.1f} °C")
        st.caption("For pure refrigerants, condensation is treated at approximately constant saturation temperature; subcooling is a separate cold-end zone.")

    with tab3:
        st.subheader("Heat-transfer coefficients and limiting side")
        htc = pd.DataFrame([
            ["Desuperheat", results["h_shell_desup_m2k"], results["hi_w_m2k"], results["U_desup_m2k"], results["limiting_des"]],
            ["Condensing", results["ho_cond_m2k"], results["hi_w_m2k"], results["U_cond_m2k"], results["limiting_cond"]],
            ["Subcooling", results["h_shell_sub_m2k"], results["hi_w_m2k"], results["U_sub_m2k"], results["limiting_sub"]],
        ], columns=["Zone", "Shell/refrigerant HTC W/m²K", "Tube/seawater HTC W/m²K", "Overall U W/m²K", "Dominant resistance"])
        st.dataframe(htc.style.format({"Shell/refrigerant HTC W/m²K":"{:.0f}", "Tube/seawater HTC W/m²K":"{:.0f}", "Overall U W/m²K":"{:.0f}"}), hide_index=True, width="stretch")
        st.caption(f"Largest resistance percentage shows whether refrigerant film, seawater film, fouling, or tube wall is controlling U. Enhanced area ratio used = {results.get('area_enhancement_ratio',1.0):.2f}×; extra condensation film multiplier used = {results.get('enhanced_cond_mult_used',1.0):.2f}×.")
        st.info(f"Shell method: {results.get('shell_method_note', 'N/A')} Condensation HTC shown includes shell correction factor {results.get('shell_correction_factor', 1):.3f} and enhanced-tube multiplier if selected.")
        rows=[]
        for zone_name, rb, lim in [("Desuperheat", results["rb_des"], results["limiting_des"]), ("Condensing", results["rb_cond"], results["limiting_cond"]), ("Subcooling", results["rb_sub"], results["limiting_sub"])]:
            row={"Zone": zone_name, "Dominant resistance": lim}
            row.update({k: round(v,1) for k,v in rb.items()})
            rows.append(row)
        st.dataframe(pd.DataFrame(rows), hide_index=True, width="stretch")
        st.info("If seawater film dominates: increase tube velocity/passes within ΔP limits. If seawater fouling dominates: use more area or cleaner fouling basis. If refrigerant film dominates: increase shell-side distribution/area or improve condensation layout. If tube wall dominates: use higher-conductivity tube material, but for seawater corrosion titanium/Cu-Ni often governs.")

    with tab4:
        geom = pd.DataFrame([
            ["Tube OD / ID / wall", f"{results['do_mm']:.2f} / {results['di_mm']:.2f} / {results['wall_mm']:.3f}", "mm"],
            ["Tube pitch", f"{results['pitch_mm']:.2f}", "mm"],
            ["Number of tubes", f"{results['n_tubes']}", ""],
            ["Tubes per pass", f"{results['tubes_per_pass']:.1f}", ""],
            ["Tube length", f"{results['tube_length_m']:.2f}", "m"],
            ["Total outside area", f"{results['area_total_m2']:.2f}", "m²"],
            ["Enhanced area ratio", f"{results.get('area_enhancement_ratio',1.0):.2f}", "× plain"],
            ["Low-fin FPI / height / thickness", f"{results.get('enhanced_fpi',0):.0f} / {results.get('enhanced_fin_height_mm',0):.2f} / {results.get('enhanced_fin_thickness_mm',0):.2f}", "FPI / mm / mm"],
            ["Plain outside area equivalent", f"{results.get('plain_area_total_m2', results['area_total_m2']):.2f}", "m²"],
            ["Enhanced area ratio", f"{results.get('area_enhancement_ratio',1):.2f}", "-"],
            ["Subcool / condense / desuperheat lengths", f"{results.get('zone_len_sub_m',0):.2f} / {results.get('zone_len_cond_m',0):.2f} / {results.get('zone_len_des_m',0):.2f}", "m"],
            ["Bundle diameter", f"{results['bundle_diameter_mm']:.1f}", "mm"],
            ["Shell ID estimate", f"{results['shell_id_mm']:.1f}", "mm"],
            ["Shell OD estimate", f"{results['shell_od_mm']:.1f}", "mm"],
            ["Heat exchanger effective tube length", f"{results['tube_length_m']:.2f}", "m"],
            ["Radial shell clearance", f"{results['shell_clearance_radial_mm']:.1f}", "mm"],
            ["Baffle spacing", f"{results['baffle_spacing_mm']:.1f}", "mm"],
            ["Baffle cut", f"{results.get('baffle_cut_pct', 0):.1f}", "%"],
            ["Baffle/window factor", f"{results.get('window_factor', 0):.3f}", "-"],
            ["Shell correction factor", f"{results.get('baffle_thermal_factor', 1):.3f}", "-"],
            ["Shell cross-flow area", f"{results['shell_cross_area_m2']:.5f}", "m²"],
            ["Suggested tube hole", f"{results['tube_hole']['suggested_hole_mm']:.3f}", "mm"],
        ], columns=["Parameter", "Value", "Unit"])
        st.dataframe(geom, hide_index=True, width="stretch")
        st.subheader("Packaging / compactness guidance")
        if results.get("package_constraint_enabled", False):
            compact = pd.DataFrame([
                ["Available package straight-tube length", f"{results['max_package_length_m']:.2f}", "m"],
                ["Current/effective tube length", f"{results['tube_length_m']:.2f}", "m"],
                ["Length / package limit ratio", f"{results['length_compact_ratio']:.2f}", "-"],
                ["Estimated tubes needed at package length", f"{results['n_tubes_for_target_length']}", "tubes"],
                ["Estimated shell ID at package length", f"{results['shell_id_for_target_length_mm']:.0f}", "mm"],
            ], columns=["Item", "Value", "Unit"])
            st.dataframe(compact, hide_index=True, width="stretch")
        else:
            st.caption("Package constraint study is OFF. The app uses the entered Tube effective length directly and does not apply a separate packaging limit.")
        tema = results["tema"]
        st.info(f"Baffle guidance: min spacing {tema['min_spacing_m']*1000:.1f} mm; max unsupported span screening {tema['max_span_m']*1000:.1f} mm. {tema['note']}")

    with tab5:
        hyd = pd.DataFrame([
            ["Seawater mass flow", f"{results['mdot_sw_kg_s']:.3f}", "kg/s"],
            ["Seawater volume flow", f"{results['vol_sw_m3h']:.2f}", "m³/h"],
            ["Seawater flow basis", f"{results.get('seawater_flow_mode', 'Auto from water ΔT')}", ""],
            ["Actual seawater ΔT", f"{results.get('actual_sw_dt_k', 0):.2f}", "K"],
            ["Refrigerant mass flow", f"{results['mdot_ref_kg_hr']:.1f}", "kg/h"],
            ["Tube velocity", f"{results['v_tube_ms']:.3f}", "m/s"],
            ["Tube Reynolds number", f"{results['Re_i']:.0f}", ""],
            ["Tube Prandtl number", f"{results['Pr_i']:.2f}", ""],
            ["Tube Nusselt number", f"{results['Nu_i']:.1f}", ""],
            ["Inside seawater HTC", f"{results['hi_w_m2k']:.0f}", "W/m²K"],
            ["Tube friction factor", f"{results['f_i']:.4f}", ""],
            ["Tube pressure drop", f"{results['dp_tube_kpa']:.1f}", "kPa"],
            ["Safe tube velocity range", f"{results['safe_limits']['Minimum tube velocity m/s']:.1f} - {results['safe_limits']['Maximum tube velocity m/s']:.1f}", "m/s"],
            ["Max allowed tube ΔP", f"{results['safe_limits']['Maximum tube-side pressure drop kPa']:.1f}", "kPa"],
            ["Shell vapor velocity", f"{results['v_shell_vapor_ms']:.3f}", "m/s"],
            ["Shell vapor Reynolds", f"{results['Re_shell_v']:.0f}", ""],
            ["Shell refrigerant ΔP", format_pressure_drop(results['dp_shell_pa']), ""],
            ["Max allowed shell ΔP", f"{results['safe_limits']['Maximum shell-side pressure drop kPa']:.1f}", "kPa"],
            ["Max allowed shell vapor velocity", f"{results['safe_limits']['Maximum shell vapor velocity m/s']:.1f}", "m/s"],
        ], columns=["Parameter", "Value", "Unit"])
        st.dataframe(hyd, hide_index=True, width="stretch")

    with tab6:
        st.subheader("Fluid properties used")
        st.write(f"Refrigerant property source: **{results['ref_props'].get('source', 'unknown')}**")
        rp = results["ref_props"]
        sp = results["sw_props"]
        props = pd.DataFrame([
            ["Refrigerant latent heat", f"{rp['h_fg']/1000:.1f}", "kJ/kg"],
            ["Refrigerant vapor density", f"{rp['rho_v']:.2f}", "kg/m³"],
            ["Refrigerant liquid density", f"{rp['rho_l']:.1f}", "kg/m³"],
            ["Refrigerant liquid viscosity", f"{rp['mu_l']:.6f}", "Pa·s"],
            ["Seawater density", f"{sp['rho']:.1f}", "kg/m³"],
            ["Seawater Cp", f"{sp['cp']:.0f}", "J/kgK"],
            ["Seawater viscosity", f"{sp['mu']:.6f}", "Pa·s"],
            ["Seawater conductivity", f"{sp['k']:.3f}", "W/mK"],
        ], columns=["Property", "Value", "Unit"])
        st.dataframe(props, hide_index=True, width="stretch")

    with tab7:
        st.subheader("Catalogue model benchmark / standard-size comparison")
        st.caption("Approximate comparison against manually entered rows from BITZER, ONDA, and Trane/ACME catalogues. Use this for benchmark and quotation guidance; verify final selection in manufacturer software.")
        matches = catalogue_matches(results, top_n=12)
        if not matches.empty:
            display = matches.copy()
            numeric_cols = ["Catalog kW", "Adjusted kW est.", "Margin %", "Water flow m3/h", "Water dP kPa", "Shell OD mm", "Length mm", "Weight kg", "Score"]
            for c in numeric_cols:
                if c in display.columns:
                    display[c] = pd.to_numeric(display[c], errors="coerce").round(2)
            st.dataframe(display[["Source", "Model", "Service", "Catalog kW", "Adjusted kW est.", "Margin %", "Water flow m3/h", "Water dP kPa", "Passes", "Shell OD mm", "Length mm", "Weight kg", "Benchmark verdict", "Material note"]], hide_index=True, width="stretch")
            best = display.iloc[0]
            st.info(f"Closest benchmark: {best['Source']} {best['Model']} — adjusted capacity estimate {best['Adjusted kW est.']:.1f} kW, margin {best['Margin %']:.1f}%.")
        st.markdown("""
        **Meaning of catalogue columns:**  \n        • **Catalog kW** = the manufacturer-published capacity at that catalogue's standard rating condition.  \n        • **Adjusted kW est.** = this app's approximate re-rating of that catalogue capacity for your selected condensing temperature, seawater inlet temperature, fouling and service severity. It is only a benchmark, not a certified rerating.  \n
        **How to use this benchmark:**  \n        • If a standard model is close, copy its shell OD/length/pass concept as a manufacturing starting point.  \n        • If all candidates are much larger, your custom design may be too conservative or using severe seawater/fouling assumptions.  \n        • If a water/glycol model appears for seawater, treat it as geometry reference only unless materials are changed to seawater service.
        """)

    with tab8:
        st.subheader("Wieland GEWA-C condenser tube catalogue")
        st.caption("Embedded copy of the uploaded Wieland GEWA-C catalogue. Use it to verify material code, tube size, d1/d4/d3/d2 geometry and kg/m before selecting a tube.")
        if st.checkbox("Show embedded Wieland GEWA-C PDF", value=False):
            render_embedded_pdf(WIELAND_CATALOGUE_PDF_B64, height=780)
        st.download_button("Download embedded Wieland GEWA-C catalogue PDF", data=base64.b64decode(WIELAND_CATALOGUE_PDF_B64), file_name="Wieland_GEWA_C_finned_tubes_for_condenser.pdf", mime="application/pdf")

    with tab9:
        st.subheader("Approximate manufacturing weight")
        wdf = pd.DataFrame([
            ["Tubes", results.get("tube_weight_kg", 0), "kg"],
            ["Shell", results.get("shell_weight_kg", 0), "kg"],
            ["Tubesheets", results.get("tubesheet_weight_kg", 0), "kg"],
            ["Baffles", results.get("baffle_weight_kg", 0), "kg"],
            ["Water boxes / covers", results.get("waterbox_weight_kg", 0), "kg"],
            ["Supports + nozzles allowance", results.get("supports_nozzles_weight_kg", 0), "kg"],
            ["Estimated dry weight", results.get("dry_weight_kg", 0), "kg"],
            ["Estimated water-filled weight", results.get("water_filled_weight_kg", 0), "kg"],
        ], columns=["Component", "Value", "Unit"])
        st.dataframe(wdf.style.format({"Value":"{:.1f}"}), hide_index=True, width="stretch")
        st.caption("Screening estimate only. It excludes exact nozzle forgings, flanges, bolts, gasket set, lifting lugs, painting/coating, nameplate, and code-test allowances.")

    with tab10:
        pdf = make_pdf_report(results)
        if pdf is None:
            st.error("ReportLab is not installed. Add reportlab to requirements.txt.")
        else:
            st.download_button("📄 Download engineering PDF report", data=pdf, file_name=f"seawater_freon_condenser_report_{datetime.now().strftime('%Y%m%d_%H%M')}.pdf", mime="application/pdf")


def main():
    st.set_page_config(page_title="Seawater Freon Condenser Engineering Tool", layout="wide")
    if not check_password():
        st.stop()
    st.title("⚓ Seawater-Cooled Freon Shell & Tube Condenser Engineering Tool")
    st.caption("Tube-side cooling water, shell-side refrigerant condenser with desuperheat / condensing / subcooling zones, hydraulics, material guidance, and PDF report.")
    if not COOLPROP_AVAILABLE:
        st.warning("CoolProp is not available, so the app is using fallback refrigerant properties. Add CoolProp to requirements.txt for better accuracy.")
    inp = sidebar_inputs()
    designer = EngineeringCondenserDesigner()
    # Always recalculate from current sidebar inputs. Previous versions kept old
    # session results until the Calculate button was pressed, which made changes
    # in seawater temperature/flow or baffle cut appear to have no effect.
    if st.button("🚀 Calculate condenser design", type="primary"):
        pass
    results = designer.calculate(inp)
    st.session_state["last_results"] = results
    show_results(results)
    st.divider()
    st.caption("Engineering note: This tool provides preliminary engineering calculations. Final manufacture requires certified thermal/mechanical review, ASME VIII/TEMA checks, nozzle loads, vibration, drawings, hydrotest/pneumatic test procedure, QA plan, and material certificates.")


if __name__ == "__main__":
    main()
